    /// wide array to the composition through [`Self::to_quote_form`] +
    /// [`crate::ast::QuoteForm::label`] at rustc time.
    pub const LABELS: [&'static str; 2] = [Self::UNQUOTE_LABEL, Self::SPLICE_LABEL];

