    #[must_use]
    pub fn iac_forge_tag(self) -> Option<&'static str> {
        self.as_quote_form()
            .map(crate::ast::QuoteForm::iac_forge_tag)
    }

    /// Project the twelve-variant [`SexpShape`] into the canonical
    /// reader-punctuation prefix string iff the shape names a homoiconic
    /// quote-family wrapper — `Quote → Some("'")`, `Quasiquote →
    /// Some("`")`, `Unquote → Some(",")`, `UnquoteSplice → Some(",@")`,
    /// every other shape (`Nil`, `List`, every atomic-payload variant)
    /// `None`. The 4-of-12 partial projection on the closed-set
    /// [`SexpShape`] algebra that surfaces
    /// [`crate::ast::QuoteForm::prefix`]'s reader-punctuation vocabulary
    /// at the outer-shape algebra level.
    ///
    /// Composition law: `self.prefix() ==
    /// self.as_quote_form().map(crate::ast::QuoteForm::prefix)` for every
    /// `self: SexpShape` — the (outer shape, reader-punctuation prefix)
    /// pairing binds through the pre-existing quote-family carving
    /// ([`Self::as_quote_form`]) composed with the closed-set prefix
    /// projection ([`crate::ast::QuoteForm::prefix`]) rather than at a
    /// parallel four-arm inline match table here — matching the posture
    /// [`Self::iac_forge_tag`] takes through
    /// [`crate::ast::QuoteForm::iac_forge_tag`] on the cross-crate
    /// canonical-form tag axis and [`Self::as_unquote_form`] takes
    /// through [`crate::ast::QuoteForm::as_unquote_form`] on the 2-of-4
    /// template-substitution subset carving. `None` on every non-quote-
    /// family shape (six atomic-payload variants + `Nil` + `List`) — the
    /// eight-shape kernel of the projection matches the kernel of
    /// [`Self::as_quote_form`] AND [`Self::iac_forge_tag`] byte-for-byte.
    ///
    /// The EIGHTH consumer of the outer-shape algebra's shape-level
    /// projection surface, sibling of [`Self::label`] (operator-facing
    /// diagnostic-label surface, all twelve arms),
    /// [`Self::hash_discriminator`] (outer-`Sexp` cache-key discriminator
    /// byte, all twelve arms → `{0..=6}`), [`Self::as_atom_kind`]
    /// (6-of-12 atomic-payload carving), [`Self::as_quote_form`]
    /// (4-of-12 quote-family carving), [`Self::as_structural_kind`]
    /// (2-of-12 structural-residual carving), [`Self::as_unquote_form`]
    /// (2-of-12 template-substitution subset carving composed through
    /// the parent quote-family carving), and [`Self::iac_forge_tag`]
    /// (4-of-12 cross-crate canonical-form tag projection). Post-lift
    /// the outer-shape algebra closes over EIGHT typed projection
    /// surfaces, each rebuilt from the SAME closed twelve-arm set — a
    /// regression that drifts ONE projection against the algebra's
    /// shape-identity fails-loudly at rustc's exhaustiveness rather than
    /// silently at runtime.
    ///
    /// Pre-lift the (SexpShape variant, reader-punctuation prefix)
    /// pairing had no typed projection at the outer-shape algebra level
    /// — a consumer with a [`SexpShape`] in hand (a
    /// [`LispError::TypeMismatch`]'s `got` slot's outer-shape identity,
    /// a rejected shape from a typed-entry gate, an LSP hover / REPL
    /// completion / audit-trail metric keyed on the observed outer
    /// shape) wanting the reader's canonical homoiconic prefix character
    /// had to re-embed the shape into a quote-family typed marker via
    /// [`Self::as_quote_form`] then compose through
    /// [`crate::ast::QuoteForm::prefix`] inline. Post-lift the
    /// composition binds at ONE method on the outer [`SexpShape`]
    /// algebra — the (outer shape, reader-punctuation prefix) pairing
    /// lives at ONE typed projection matching the shape-level algebra
    /// sweep the seven sibling projections established.
    ///
    /// The `Option<&'static str>` return shape is the natural typed peer
    /// of [`crate::ast::QuoteForm::prefix`]'s total `&'static str`
    /// return: the quote-family superset TOTALS on the four-arm closed
    /// set, and the outer twelve-arm closed set's projection PARTIALIZES
    /// on the eight non-quote-family shapes. Same shape as
    /// [`Self::as_atom_kind`] / [`Self::as_quote_form`] /
    /// [`Self::as_structural_kind`] / [`Self::as_unquote_form`] /
    /// [`Self::iac_forge_tag`] — each carving lifts a total sub-algebra
    /// projection to a partial outer-shape projection with `None` on
    /// the residual arms, so a consumer keying on "iff this outer shape
    /// has a canonical reader-punctuation prefix" binds against the
    /// closed set's typed image directly rather than substring-matching
    /// the shape label.
    ///
    /// The reader-punctuation vocabulary this method projects (`"'"` /
    /// `` "`" `` / `","` / `",@"`) is INTENTIONALLY DISJOINT from the
    /// two sibling `&'static str` projection axes:
    ///
    /// * [`Self::iac_forge_tag`] — cross-crate canonical form
    ///   (`"quote"` / `"quasiquote"` / `"unquote"` /
    ///   `"unquote-splicing"`), BLAKE3 attestation keys, render-cache
    ///   shape (load-bearing for byte-identical inter-crate compatibility
    ///   with the iac-forge ecosystem).
    /// * [`Self::label`] — operator-facing diagnostic label (`"quote"` /
    ///   `"quasiquote"` / `"unquote"` / `"unquote-splice"`),
    ///   [`LispError::TypeMismatch`]'s `got` rendering, REPL / LSP
    ///   shape-of-witness surface.
    ///
    /// This method projects the reader's SOURCE-TEXT vocabulary — the
    /// four punctuation characters that appear literally in Lisp source
    /// at each variant's homoiconic prefix. The three closed-set
    /// projections key the SAME twelve-arm shape algebra on THREE
    /// distinct `&'static str` vocabularies (source-punctuation,
    /// diagnostic-label, cross-crate canonical-form); consolidating any
    /// two would silently break either the reader round-trip, the
    /// operator-facing diagnostic surface, OR the iac-forge attestation
    /// pipeline. The three vocabularies' distinctness is pinned bit-for-
    /// bit through the composition law across the closed-set typed
    /// algebra.
    ///
    /// The `&'static str` lifetime is load-bearing: every reader / LSP
    /// / REPL / diagnostic consumer projects through this method into
    /// the canonical prefix character without an allocation, parallel to
    /// how [`crate::ast::QuoteForm::prefix`] on the sub-carving,
    /// [`Self::iac_forge_tag`] on the cross-crate canonical-form axis,
    /// [`Self::label`] on the outer-shape diagnostic surface, and
    /// [`UnquoteForm::marker`] on the template marker axis project their
    /// respective closed sets. A future homoiconic prefix-wrapper (e.g.
    /// hypothetical `,~` reverse-unquote) extends
    /// [`crate::ast::QuoteForm`] AND [`Self`]'s closed set together —
    /// rustc binds the reader-punctuation surface to the extended
    /// algebra at ONE arm each through exhaustiveness, with the
    /// composition through [`Self::as_quote_form`] pulling the new
    /// variant's prefix into this projection mechanically.
    ///
    /// Theory anchor: THEORY.md §V.1 — knowable platform; the
    /// (SexpShape variant, reader-punctuation prefix) pairing becomes a
    /// TYPE projection on the outer-shape algebra rather than an inline
    /// `.as_quote_form().map(...)` two-step at every consumer. A typo
    /// or swap at the projection site is no longer a runtime prefix
    /// drift but a compile error against the typed composition — the
    /// `SexpShape` ↔ `QuoteForm` ↔ prefix character chain is
    /// rustc-enforced end-to-end. THEORY.md §II.1 invariant 2 — free
    /// middle; the (outer shape, reader-punctuation prefix) pairing now
    /// binds at ONE site on the outer-shape algebra, composing through
    /// the pre-existing four-arm sub-carving's prefix projection rather
    /// than duplicating the four-arm match here. THEORY.md §VI.1 —
    /// generation over composition; the outer-shape algebra's typed
    /// projection surface closes over EIGHT methods (label,
    /// hash_discriminator, four carvings, iac_forge_tag, prefix) each
    /// keyed on the SAME closed twelve-arm set.
    ///
    /// Frontier inspiration: MLIR's `mlir::TypeSwitch<T>` typed
    /// pattern-match combinator on a closed union — narrowing to a
    /// specific typed case yields the typed downcast + operations on
    /// that case in ONE typed step. [`Self::prefix`] is the Rust-typed
    /// peer where the "narrow to quote-family" step
    /// ([`Self::as_quote_form`]) composes with the "read the case's
    /// reader-punctuation prefix" step
    /// ([`crate::ast::QuoteForm::prefix`]) into ONE outer-shape
    /// projection. Racket's `(match shape [(? quote-shape? qs)
    /// (quote-shape->reader-prefix qs)] [_ #f])` closed-form match on
    /// the shape-taxonomy union — the outer pattern's partial projection
    /// to the source-punctuation form IS the shape this method lifts to
    /// a typed Rust closed-set match.
    #[must_use]
    pub fn prefix(self) -> Option<&'static str> {
        self.as_quote_form().map(crate::ast::QuoteForm::prefix)
    }

    /// Project the typed [`SexpShape`] into the outer-`Sexp`
    /// [`Hash for Sexp`](crate::ast::Sexp) cache-key discriminator byte
    /// `{0..=6}` — the SHAPE-LEVEL peer of
    /// [`crate::ast::Sexp::hash_discriminator`] one algebra level up.
    /// The twelve outer-shape arms collapse to seven outer bytes: the six
    /// atomic-payload arms (`Symbol`, `Keyword`, `String`, `Int`, `Float`,
    /// `Bool`) all project to the outer Atom marker byte `1u8` (their
    /// per-atom-kind inner byte lives nested inside
    /// [`Hash for Atom`](crate::ast::Atom) via
    /// [`crate::ast::AtomKind::hash_discriminator`]'s `{0..=5}` payload
    /// carving, NOT surfaced here); the two structural-residual arms
    /// (`Nil`, `List`) delegate through
    /// [`StructuralKind::hash_discriminator`] for `{0, 2}`; the four
    /// quote-family arms (`Quote`, `Quasiquote`, `Unquote`,
    /// `UnquoteSplice`) delegate through
    /// [`crate::ast::QuoteForm::hash_discriminator`] for `{3..=6}`. The
    /// byte partition is byte-identical to
    /// [`crate::ast::Sexp::hash_discriminator`]'s outer sweep, so the
    /// substrate's macro-expansion cache
    /// ([`crate::macro_expand::Expander`]'s cache) key stays bit-for-bit
    /// stable across the shape-level lift.
    ///
    /// Composition law: `sexp.hash_discriminator() ==
    /// sexp.shape().hash_discriminator()` for every `sexp: &Sexp` — the
    /// outer-`Sexp` cache-key discriminator method routes through
    /// [`crate::ast::Sexp::shape`] into THIS method, which in turn
    /// routes into the three closed-set carvings' discriminator
    /// methods. Post-lift the outer-`Sexp` cache-key algebra closes at
    /// FIVE typed layers:
    ///   1. [`crate::ast::Sexp::hash_discriminator`] — 7-arm outer
    ///      dispatch on the outer `Sexp` algebra;
    ///   2. [`Self::hash_discriminator`] — 12-arm shape-level dispatch on
    ///      the [`SexpShape`] algebra (this method);
    ///   3. [`StructuralKind::hash_discriminator`] — 2-arm
    ///      structural-residual sub-carving for `{0, 2}`;
    ///   4. [`crate::ast::QuoteForm::hash_discriminator`] — 4-arm
    ///      quote-family sub-carving for `{3..=6}`;
    ///   5. [`crate::ast::AtomKind::hash_discriminator`] — 6-arm
    ///      atomic-payload sub-carving for `{0..=5}` (nested inside
    ///      `Hash for Atom` under outer byte `1u8`, NOT surfaced through
    ///      this shape-level method).
    ///
    /// Pre-lift the outer-`Sexp` cache-key algebra bottomed out at the
    /// three sub-carvings' discriminator methods directly via
    /// [`crate::ast::Sexp::hash_discriminator`]'s seven arms — no
    /// intermediate shape-level projection existed. Consumers that had a
    /// typed [`SexpShape`] identity in hand (a
    /// `LispError::TypeMismatch.got` slot, a rejected shape from a
    /// typed-entry gate, a future authoring-tool audit-trail metric keyed
    /// on the observed shape) wanting the outer cache-key byte had to
    /// re-embed the typed shape into a [`crate::ast::Sexp`] value and
    /// route through the outer method — an unnecessary allocation. Post-
    /// lift the shape-level projection is a NAMED PRIMITIVE on the closed-
    /// set [`SexpShape`] algebra sitting next to the three sibling shape-
    /// level projections ([`Self::label`], [`Self::as_atom_kind`],
    /// [`Self::as_quote_form`], [`Self::as_structural_kind`],
    /// [`Self::as_unquote_form`]) — the outer cache-key partition
    /// becomes a typed identity on the shape algebra rather than a
    /// projection through the outer-`Sexp` value carrier.
    ///
    /// `pub(crate)` because the byte-discriminator surface is an
    /// implementation detail of the substrate's `Hash for Sexp` cache-
    /// key contract; exposing it publicly would leak the cache-key shape
    /// through the API without enabling any external consumer the public
    /// projections ([`Self::label`], [`Self::as_atom_kind`],
    /// [`Self::as_quote_form`], [`Self::as_structural_kind`]) don't
    /// already serve. Same posture as
    /// [`crate::ast::Sexp::hash_discriminator`],
    /// [`crate::ast::AtomKind::hash_discriminator`],
    /// [`crate::ast::QuoteForm::hash_discriminator`], and
    /// [`StructuralKind::hash_discriminator`].
    ///
    /// A future thirteenth [`SexpShape`] variant (e.g. `Vector` for
    /// `#(...)` reader syntax, `Map` for `{...}`, `Char` for `#\x`)
    /// picks a fresh cache-key byte outside `{0..=6}` (e.g. `7u8`),
    /// extends either [`StructuralKind`] / [`crate::ast::AtomKind`] /
    /// [`crate::ast::QuoteForm`] (if it names an existing sub-carving)
    /// or a fresh sub-algebra, and lands at ONE new arm here — rustc
    /// binds the consistency through exhaustiveness over the closed
    /// [`SexpShape`] enum.
    ///
    /// Theory anchor: THEORY.md §V.1 — knowable platform; the
    /// (SexpShape variant, outer cache-key byte) pairing becomes a TYPE
    /// projection on the substrate's shape algebra rather than requiring
    /// a re-embed into [`crate::ast::Sexp`] followed by an outer
    /// dispatch. A typo or swap at the shape-level projection site is
    /// a compile error against the typed projection rather than a
    /// silent runtime cache-key drift. THEORY.md §II.1 invariant 2 —
    /// free middle; the outer-`Sexp` cache-key algebra now closes over
    /// FIVE typed layers (outer, shape, three sub-carvings) with rustc-
    /// enforced consistency across each — a regression that drifts ONE
    /// layer's discriminator bytes from the others cannot reach the
    /// substrate's runtime cache. THEORY.md §VI.1 — generation over
    /// composition; the shape-level projection is the missing algebra
    /// layer between the outer-`Sexp` and the three sub-carvings — the
    /// four pre-existing typed layers become a full FIVE-layer typed
    /// composition through ONE new named projection.
    #[must_use]
    pub(crate) fn hash_discriminator(self) -> u8 {
        match self {
            Self::Nil => StructuralKind::Nil.hash_discriminator(),
            Self::List => StructuralKind::List.hash_discriminator(),
            Self::Symbol | Self::Keyword | Self::String | Self::Int | Self::Float | Self::Bool => {
                crate::ast::AtomKind::OUTER_HASH_DISCRIMINATOR
            }
            Self::Quote => crate::ast::QuoteForm::Quote.hash_discriminator(),
            Self::Quasiquote => crate::ast::QuoteForm::Quasiquote.hash_discriminator(),
            Self::Unquote => crate::ast::QuoteForm::Unquote.hash_discriminator(),
            Self::UnquoteSplice => crate::ast::QuoteForm::UnquoteSplice.hash_discriminator(),
        }
    }

    /// Canonical `u8` outer-`Sexp` cache-key byte for the [`Self::Nil`]
    /// outer shape — aliases [`StructuralKind::NIL_HASH_DISCRIMINATOR`]
    /// on the StructuralKind ⊂ SexpShape carving so the marker-level
    /// byte binds at ONE `pub(crate) const` on the SUB-CARVING's
    /// per-role primitive rather than at TWO sites (the sub-carving's
    /// per-role byte AND a parallel outer-shape inline literal). The
    /// canonical source of the byte lives on the sub-carving; this
    /// outer-shape peer alias projects it into the twelve-arm
    /// [`SexpShape`] algebra at zero-drift cost.
    ///
    /// Sibling posture to the twelve peer per-role `*_LABEL` aliases
    /// on [`Self`] — the `Nil` outer-shape per-role LABEL is canonical
    /// on [`Self`] and is aliased INTO [`StructuralKind::NIL_LABEL`];
    /// this per-role HASH_DISCRIMINATOR alias runs in the OPPOSITE
    /// direction because the outer-`Sexp` cache-key byte's canonical
    /// source is the sub-carving (which the outer `Sexp` dispatch
    /// composes through). The load-bearing invariant across the two
    /// axes is byte-identity: the outer-shape peer alias equals the
    /// sub-carving's canonical byte at rustc-time through the
    /// `const` initializer.
    pub(crate) const NIL_HASH_DISCRIMINATOR: u8 = StructuralKind::NIL_HASH_DISCRIMINATOR;

    /// Canonical `u8` outer-`Sexp` cache-key byte for the [`Self::Symbol`]
    /// outer shape — aliases [`crate::ast::AtomKind::OUTER_HASH_DISCRIMINATOR`]
    /// on the AtomKind ⊂ SexpShape carving. Every atomic-payload outer
    /// shape shares this outer marker byte because the per-atom-kind
    /// specialisation lives at the NESTED INNER
    /// [`crate::ast::AtomKind::HASH_DISCRIMINATORS`] `{0..=5}` carve
    /// inside `Hash for Atom`, NOT surfaced through this outer shape-
    /// level projection.
    pub(crate) const SYMBOL_HASH_DISCRIMINATOR: u8 = crate::ast::AtomKind::OUTER_HASH_DISCRIMINATOR;

    /// Canonical `u8` outer-`Sexp` cache-key byte for the [`Self::Keyword`]
    /// outer shape — aliases [`crate::ast::AtomKind::OUTER_HASH_DISCRIMINATOR`]
    /// on the AtomKind ⊂ SexpShape carving. Six-way collapse peer of
    /// [`Self::SYMBOL_HASH_DISCRIMINATOR`].
    pub(crate) const KEYWORD_HASH_DISCRIMINATOR: u8 =
        crate::ast::AtomKind::OUTER_HASH_DISCRIMINATOR;

    /// Canonical `u8` outer-`Sexp` cache-key byte for the [`Self::String`]
    /// outer shape — aliases [`crate::ast::AtomKind::OUTER_HASH_DISCRIMINATOR`].
    /// Six-way collapse peer.
    pub(crate) const STRING_HASH_DISCRIMINATOR: u8 = crate::ast::AtomKind::OUTER_HASH_DISCRIMINATOR;

    /// Canonical `u8` outer-`Sexp` cache-key byte for the [`Self::Int`]
    /// outer shape — aliases [`crate::ast::AtomKind::OUTER_HASH_DISCRIMINATOR`].
    /// Six-way collapse peer.
    pub(crate) const INT_HASH_DISCRIMINATOR: u8 = crate::ast::AtomKind::OUTER_HASH_DISCRIMINATOR;

    /// Canonical `u8` outer-`Sexp` cache-key byte for the [`Self::Float`]
    /// outer shape — aliases [`crate::ast::AtomKind::OUTER_HASH_DISCRIMINATOR`].
    /// Six-way collapse peer.
    pub(crate) const FLOAT_HASH_DISCRIMINATOR: u8 = crate::ast::AtomKind::OUTER_HASH_DISCRIMINATOR;

    /// Canonical `u8` outer-`Sexp` cache-key byte for the [`Self::Bool`]
    /// outer shape — aliases [`crate::ast::AtomKind::OUTER_HASH_DISCRIMINATOR`].
    /// Six-way collapse peer of the atomic-outer sextet.
    pub(crate) const BOOL_HASH_DISCRIMINATOR: u8 = crate::ast::AtomKind::OUTER_HASH_DISCRIMINATOR;

    /// Canonical `u8` outer-`Sexp` cache-key byte for the [`Self::List`]
    /// outer shape — aliases [`StructuralKind::LIST_HASH_DISCRIMINATOR`]
    /// on the StructuralKind ⊂ SexpShape carving. Structural-residual
    /// peer of [`Self::NIL_HASH_DISCRIMINATOR`]; the gap at `1u8`
    /// between the two structural-residual bytes reserves the outer
    /// atomic-carve byte the six-way atomic-outer sextet collapses to.
    pub(crate) const LIST_HASH_DISCRIMINATOR: u8 = StructuralKind::LIST_HASH_DISCRIMINATOR;

    /// Canonical `u8` outer-`Sexp` cache-key byte for the [`Self::Quote`]
    /// outer shape — aliases [`crate::ast::QuoteForm::QUOTE_HASH_DISCRIMINATOR`]
    /// on the QuoteForm ⊂ SexpShape carving.
    pub(crate) const QUOTE_HASH_DISCRIMINATOR: u8 = crate::ast::QuoteForm::QUOTE_HASH_DISCRIMINATOR;

    /// Canonical `u8` outer-`Sexp` cache-key byte for the
    /// [`Self::Quasiquote`] outer shape — aliases
    /// [`crate::ast::QuoteForm::QUASIQUOTE_HASH_DISCRIMINATOR`].
    pub(crate) const QUASIQUOTE_HASH_DISCRIMINATOR: u8 =
        crate::ast::QuoteForm::QUASIQUOTE_HASH_DISCRIMINATOR;

    /// Canonical `u8` outer-`Sexp` cache-key byte for the [`Self::Unquote`]
    /// outer shape — aliases [`crate::ast::QuoteForm::UNQUOTE_HASH_DISCRIMINATOR`].
    pub(crate) const UNQUOTE_HASH_DISCRIMINATOR: u8 =
        crate::ast::QuoteForm::UNQUOTE_HASH_DISCRIMINATOR;

    /// Canonical `u8` outer-`Sexp` cache-key byte for the
