    // ── KwargDeserialize: typed-entry `from_value` structural-variant lift ──
    //
    // `deserialize_err(key, err)` and `deserialize_item_err(key, idx,
    // err)` (the `from_value`-side gate shared between
    // `extract_via_serde`, `extract_optional_via_serde`, and
    // `extract_vec_via_serde`) were promoted from the
    // `LispError::Compile`-shaped triple to the structural
    // `LispError::KwargDeserialize { path: KwargPath, message }`
    // variant — the `(key: String, idx: Option<usize>)` bifurcation
    // collapsed into the typed `KwargPath` enum's `Named` vs. `Item`
    // variant identity. The tests below pin: (a) Display matches the
    // legacy `"compile error in :{key}: deserialize: {message}"` shape
    // byte-for-byte for the scalar path (`path: KwargPath::Named`); (b)
    // Display matches the indexed `"compile error in :{key}[{idx}]:
    // deserialize: {message}"` shape byte-for-byte for the per-item
    // path (`path: KwargPath::Item`); (c) the legacy substring
    // `"deserialize: "` and the legacy prefix `"compile error in :"`
    // both survive the lift unchanged for substring-grep consumers;
    // (d) kebab-case keys thread through unchanged; (e) the typed
    // `path` slot carries `KwargPath` data DIRECTLY (not as a projection
    // through a helper), structurally bound via pattern-match on the
    // typed enum's variant identity. The `position()` floor is pinned
    // in the main `position_is_none_for_non_positional_variants` block
    // above.

    #[test]
    fn kwarg_deserialize_display_scalar_path_renders_legacy_shape() {
        // `path: KwargPath::Named(_)` — scalar / `Option<T>` path. The
        // variant renders the legacy `"compile error in :{key}:
        // deserialize: {message}"` shape byte-for-byte. Same wording as
        // the pre-lift `Compile`-shaped triple in `deserialize_err`.
        let err = LispError::KwargDeserialize {
            path: KwargPath::named("level"),
            message: "unknown variant `NotASeverity`".into(),
        };
        assert_eq!(
            format!("{err}"),
            "compile error in :level: deserialize: unknown variant `NotASeverity`"
        );
    }

    #[test]
    fn kwarg_deserialize_display_per_item_path_renders_indexed_shape() {
        // `path: KwargPath::Item { .. }` — per-item path. The variant
        // renders the legacy `"compile error in :{key}[{idx}]:
        // deserialize: {message}"` shape byte-for-byte. Same wording as
        // the pre-lift `Compile`-shaped triple in `deserialize_item_err`.
        let err = LispError::KwargDeserialize {
            path: KwargPath::item("steps", 1),
            message: "invalid type: integer `7`, expected a string".into(),
        };
        assert_eq!(
            format!("{err}"),
            "compile error in :steps[1]: deserialize: invalid type: integer `7`, expected a string"
        );
    }

    #[test]
    fn kwarg_deserialize_display_carries_serde_json_diagnostic_unchanged() {
        // Use a real `serde_json::Error` so the test exercises a
        // representative `{e}` shape (`"expected value at line L
        // column C"`) and pins that the variant's Display rendering
        // threads the underlying diagnostic through unchanged.
        let raw = serde_json::from_str::<i32>("not-a-number")
            .expect_err("parse must fail")
            .to_string();
        let err = LispError::KwargDeserialize {
            path: KwargPath::named("count"),
            message: raw.clone(),
        };
        assert_eq!(
            format!("{err}"),
            format!("compile error in :count: deserialize: {raw}")
        );
    }

    #[test]
    fn kwarg_deserialize_display_carries_kebab_case_key_unchanged() {
        // Kebab-cased kwarg names (`notify-ref`, `wait-minutes`,
        // `window-seconds`) round-trip through the rendered diagnostic's
        // `compile error in :{key}:` prefix unchanged. A regression that
        // camelCases the key fails-loudly here.
        let err = LispError::KwargDeserialize {
            path: KwargPath::named("notify-ref"),
            message: "missing field `notify-ref`".into(),
        };
        assert_eq!(
            format!("{err}"),
            "compile error in :notify-ref: deserialize: missing field `notify-ref`"
        );
    }

    #[test]
    fn kwarg_deserialize_display_carries_kebab_case_key_with_index_unchanged() {
        // Kebab-cased keys round-trip through the indexed path too —
        // `:notify-refs[2]` not `:notifyRefs[2]`. Pinning both paths
        // means a regression in either site (scalar or per-item) fails-
        // loudly here.
        let err = LispError::KwargDeserialize {
            path: KwargPath::item("wait-minutes", 2),
            message: "expected u64".into(),
        };
        assert_eq!(
            format!("{err}"),
            "compile error in :wait-minutes[2]: deserialize: expected u64"
        );
    }

    #[test]
    fn kwarg_deserialize_display_preserves_legacy_substring_for_message_grep() {
        // Pin the legacy substring — `"deserialize: "` — as a separate
        // assertion so a regression that drifts the wording (e.g., to
        // "from_json failed", "json decode error") fails-loudly here.
        // The substring is what consumers downstream (`tatara-check`,
        // the REPL) substring-match on; the prefix matches the legacy
        // `Compile { form: kwarg_form(key), message: format!("deserialize:
        // {e}") }` byte-for-byte. Both sub-modes (`KwargPath::Named`
        // AND `KwargPath::Item`) preserve the substring.
        let scalar = LispError::KwargDeserialize {
            path: KwargPath::named("level"),
            message: "boom".into(),
        };
        let scalar_msg = format!("{scalar}");
        assert!(
            scalar_msg.contains("deserialize: "),
            "expected legacy substring in scalar message, got: {scalar_msg}"
        );
        assert!(
            scalar_msg.contains("compile error in :level:"),
            "expected legacy form-label prefix in scalar message, got: {scalar_msg}"
        );

        let item = LispError::KwargDeserialize {
            path: KwargPath::item("steps", 3),
            message: "boom".into(),
        };
        let item_msg = format!("{item}");
        assert!(
            item_msg.contains("deserialize: "),
            "expected legacy substring in item message, got: {item_msg}"
        );
        assert!(
            item_msg.contains("compile error in :steps[3]:"),
            "expected indexed form-label prefix in item message, got: {item_msg}"
        );
    }

    #[test]
    fn kwarg_deserialize_display_zero_index_is_first_class() {
        // Edge case: `path: KwargPath::Item { idx: 0, .. }` must render
        // as `:steps[0]`, not `:steps` (which would collide with the
        // scalar path's `KwargPath::Named` rendering). Pin that the
        // bifurcation is by `KwargPath` variant identity, not by
        // `idx > 0`.
        let err = LispError::KwargDeserialize {
            path: KwargPath::item("steps", 0),
            message: "bad".into(),
        };
        assert_eq!(
            format!("{err}"),
            "compile error in :steps[0]: deserialize: bad"
        );
    }

    #[test]
    fn kwarg_deserialize_path_named_threads_typed_kwarg_path_through_variant_slot() {
        // Structural pin: the scalar / `Option<T>` path's
        // `LispError::KwargDeserialize` carries the typed
        // `KwargPath::Named(key)` value DIRECTLY in its `path` slot,
        // not a `(key: String, idx: None)` pair. Authoring tools (REPL,
        // LSP, `tatara-check`) bind on the typed enum's variant
        // identity (`KwargPath::Named(_)`) rather than substring-
        // matching the rendered `form:` prefix, parallel to how
        // `TypeMismatch.form` is bound. A regression that re-bifurcates
        // the variant into a `(key, idx: Option<usize>)` pair fails the
        // structural assertion here (the slot would no longer be a
        // typed `KwargPath`).
        let err = LispError::KwargDeserialize {
            path: KwargPath::named("level"),
            message: "boom".into(),
        };
        let LispError::KwargDeserialize {
            ref path,
            ref message,
        } = err
        else {
            panic!("expected KwargDeserialize, got {err:?}");
        };
        assert_eq!(*path, KwargPath::Named("level".into()));
        assert_eq!(message, "boom");
        assert_eq!(
            format!("{err}"),
            "compile error in :level: deserialize: boom"
        );
    }

    #[test]
    fn kwarg_deserialize_path_item_threads_typed_kwarg_path_through_variant_slot() {
        // Sibling structural pin to `…_path_named_…`: the per-item path
        // carries `KwargPath::Item { key, idx }` directly in its `path`
        // slot. The `(key, idx)` bifurcation lives inside the typed
        // enum's variant identity (`KwargPath::Named` vs.
        // `KwargPath::Item`), so the invalid sibling slot combination
        // `(key: "", idx: Some(_))` for a scalar / Optional path is
        // structurally unrepresentable in the variant's data shape.
        let err = LispError::KwargDeserialize {
            path: KwargPath::item("steps", 1),
            message: "bad".into(),
        };
        let LispError::KwargDeserialize {
            ref path,
            ref message,
        } = err
        else {
            panic!("expected KwargDeserialize, got {err:?}");
        };
        assert_eq!(
            *path,
            KwargPath::Item {
                key: "steps".into(),
                idx: 1
            }
        );
        assert_eq!(message, "bad");
        assert_eq!(
            format!("{err}"),
            "compile error in :steps[1]: deserialize: bad"
        );
    }

    #[test]
    fn kwarg_deserialize_display_prefix_matches_kwarg_path_display() {
        // End-to-end pin: the `LispError::KwargDeserialize` variant's
        // Display rendering threads its typed `path: KwargPath` slot
        // through `KwargPath`'s `Display` impl directly (via the
        // `#[error("compile error in {path}: ...")]` annotation, no
        // intermediate helper). The full rendered diagnostic MUST be
        // anchored on the canonical `KwargPath`-projected prefix
        // across BOTH variants of `KwargPath` — a regression that
        // drifts either projection (e.g., re-introducing an inline
        // `format!` literal in a `#[error(..., fmt_fn(path))]` annotation
        // that diverges from `KwargPath`'s Display arm) fails-loudly
        // here.
        let scalar = LispError::KwargDeserialize {
            path: KwargPath::named("level"),
            message: "boom".into(),
        };
        assert_eq!(
            format!("{scalar}"),
            format!(
                "compile error in {}: deserialize: boom",
                KwargPath::named("level")
            )
        );

        let item = LispError::KwargDeserialize {
            path: KwargPath::item("steps", 3),
            message: "boom".into(),
        };
        assert_eq!(
            format!("{item}"),
            format!(
                "compile error in {}: deserialize: boom",
                KwargPath::item("steps", 3)
            )
        );
    }

    // ── CompilerSpecIo: disk-persistence structural-variant lift ────
    //
    // `compiler_spec_io_err` (the helper shared by all four
    // `realize_to_disk` / `load_from_disk` call sites in
    // `compiler_spec.rs`) was promoted from the `LispError::Compile`-
    // shaped triple to the structural `LispError::CompilerSpecIo {
    // stage, message }` variant — closing the LAST
    // `LispError::Compile { ... }` construction site in
    // `tatara-lisp/src/compiler_spec.rs`. The `stage` slot is the
    // typed closed-set `CompilerSpecIoStage` enum, so the
    // (operation, stage) pair is structurally constrained — only the
    // four reachable pairs (`realize_to_disk` × {serialize, write}
    // ⊎ `load_from_disk` × {read, deserialize}) are representable
    // in the variant.
    //
    // The tests below pin: (a) Display matches the legacy `"compile
    // error in {operation}: {stage}: {message}"` shape byte-for-byte
    // across all four stages; (b) the closed-set `operation()` /
    // `label()` projections; (c) the `CompilerSpecIoStage` enum is
    // Copy + Eq + Debug (matches the `MacroDefHead` posture); (d) the
    // legacy substring `"realize_to_disk"`, `"load_from_disk"`,
    // `"serialize: "`, `"write: "`, `"read: "`, `"deserialize: "`
    // survive the lift unchanged for substring-grep consumers. The
    // `position()` floor for both representative stages is pinned in
    // the main `position_is_none_for_non_positional_variants` block
    // above.

    #[test]
    fn compiler_spec_io_stage_operation_projects_realize_for_serialize_and_write() {
        // Both `realize_to_disk` stages share the same `operation()`
        // projection. Pin the closed-set posture: the operation slot
        // of the legacy `Compile`-shaped triple is now a TYPED
        // projection from `CompilerSpecIoStage`, not an
        // independently-passed `&'static str` that could drift.
        assert_eq!(
            super::CompilerSpecIoStage::RealizeToDiskSerialize.operation(),
            "realize_to_disk"
        );
        assert_eq!(
            super::CompilerSpecIoStage::RealizeToDiskWrite.operation(),
            "realize_to_disk"
        );
    }

    #[test]
    fn compiler_spec_io_stage_operation_projects_load_for_read_and_deserialize() {
        // Both `load_from_disk` stages share the same `operation()`
        // projection. Sibling to the realize-side assertion: pins the
        // bifurcation of the closed set by `operation()` is exhaustive
        // and exactly 2-way (`realize_to_disk` ⊎ `load_from_disk`).
        assert_eq!(
            super::CompilerSpecIoStage::LoadFromDiskRead.operation(),
            "load_from_disk"
        );
        assert_eq!(
            super::CompilerSpecIoStage::LoadFromDiskDeserialize.operation(),
            "load_from_disk"
        );
    }

    #[test]
    fn compiler_spec_io_stage_label_projects_canonical_stage_strings() {
        // Each `CompilerSpecIoStage` projects to its canonical
        // `label()` — the `{stage}` slot of the legacy `"{stage}:
        // {error}"` message. Pin all four projections so a regression
        // that drifts ANY label (e.g., to "ser", "load", "decode",
        // "json-out") fails-loudly here. The four labels are the
        // surface that `tatara-check`'s diagnostic capture and the
        // REPL substring-grep on today.
        assert_eq!(
            super::CompilerSpecIoStage::RealizeToDiskSerialize.label(),
            "serialize"
        );
        assert_eq!(
            super::CompilerSpecIoStage::RealizeToDiskWrite.label(),
            "write"
        );
        assert_eq!(super::CompilerSpecIoStage::LoadFromDiskRead.label(), "read");
        assert_eq!(
            super::CompilerSpecIoStage::LoadFromDiskDeserialize.label(),
            "deserialize"
        );
    }

    #[test]
    fn compiler_spec_io_stage_label_method_routes_through_typed_constants() {
        // PATH-UNIFORMITY: the inherent `Self::label(self)` method
        // MUST return the per-role `pub const` byte-for-byte for
        // each reachable variant. A regression that reverts ONE arm
        // to an inline `"serialize"` string literal (e.g. a merge-
        // conflict resolution that picked the pre-lift form)
        // silently reintroduces the ≥2 PRIME-DIRECTIVE trigger the
        // lift resolved — this test catches that by pinning the
        // arm's return value to the constant, so the two paths
        // (inline vs. typed constant) cannot both hold. Sibling
        // posture to
        // `kwarg_path_kind_label_method_routes_through_typed_constants`
        // on the `KwargPathKind` category-label algebra.
        assert_eq!(
            super::CompilerSpecIoStage::RealizeToDiskSerialize.label(),
            super::CompilerSpecIoStage::REALIZE_TO_DISK_SERIALIZE_LABEL,
            "CompilerSpecIoStage::RealizeToDiskSerialize.label() \
             drifted from CompilerSpecIoStage::\
             REALIZE_TO_DISK_SERIALIZE_LABEL — the match arm reverted \
             to an inline literal"
        );
        assert_eq!(
            super::CompilerSpecIoStage::RealizeToDiskWrite.label(),
            super::CompilerSpecIoStage::REALIZE_TO_DISK_WRITE_LABEL,
            "CompilerSpecIoStage::RealizeToDiskWrite.label() drifted \
             from CompilerSpecIoStage::REALIZE_TO_DISK_WRITE_LABEL — \
             the match arm reverted to an inline literal"
        );
        assert_eq!(
            super::CompilerSpecIoStage::LoadFromDiskRead.label(),
            super::CompilerSpecIoStage::LOAD_FROM_DISK_READ_LABEL,
            "CompilerSpecIoStage::LoadFromDiskRead.label() drifted \
             from CompilerSpecIoStage::LOAD_FROM_DISK_READ_LABEL — \
             the match arm reverted to an inline literal"
        );
        assert_eq!(
            super::CompilerSpecIoStage::LoadFromDiskDeserialize.label(),
            super::CompilerSpecIoStage::LOAD_FROM_DISK_DESERIALIZE_LABEL,
            "CompilerSpecIoStage::LoadFromDiskDeserialize.label() \
             drifted from CompilerSpecIoStage::\
             LOAD_FROM_DISK_DESERIALIZE_LABEL — the match arm reverted \
             to an inline literal"
        );
    }

    #[test]
    fn compiler_spec_io_stage_labels_has_expected_cardinality() {
        // Cardinality contract: `Self::LABELS.len() == 4` — pinned
        // at the declaration site by rustc's forced-arity check on
        // `[&'static str; 4]`. This test surfaces the arity as a
        // fail-loud runtime pin so a future refactor that switches
        // the array type to `&[&'static str]` (dropping the
        // compile-time arity forcing) doesn't silently loosen the
        // closed-set discipline the family relies on. Sibling
        // posture to `kwarg_path_kind_labels_has_expected_cardinality`
        // on the `KwargPathKind::LABELS` family.
        assert_eq!(
            super::CompilerSpecIoStage::LABELS.len(),
            4,
            "CompilerSpecIoStage::LABELS cardinality drifted from 4 \
             — the disk-persistence stage-label closed set gained or \
             lost a variant without the ALL / LABELS pair being \
             updated in tandem"
        );
    }

    #[test]
    fn compiler_spec_io_stage_labels_align_with_all_by_index() {
        // ALIGNMENT CONTRACT: `Self::LABELS[i] ==
        // Self::ALL[i].label()` element-wise. The two ALL arrays
        // (typed variants, canonical `&'static str` labels) share
        // ONE canonical declaration order — a regression that
        // reorders ONE array without reordering the other silently
        // misaligns every `zip(Self::ALL, Self::LABELS)` consumer
        // (LSP completion providers, metric-label emitters, coverage
        // reporters). Pinning by-index alignment here catches the
        // reorder at test time. Sibling posture to
        // `kwarg_path_kind_labels_align_with_all_by_index` on the
        // `KwargPathKind::LABELS` family.
        assert_eq!(
            super::CompilerSpecIoStage::LABELS.len(),
            super::CompilerSpecIoStage::ALL.len(),
            "CompilerSpecIoStage::LABELS and CompilerSpecIoStage::ALL \
             diverged in cardinality — the per-role constants and \
             enum variants must stay in lockstep"
        );
        for (i, stage) in super::CompilerSpecIoStage::ALL.iter().enumerate() {
            assert_eq!(
                super::CompilerSpecIoStage::LABELS[i],
                stage.label(),
                "CompilerSpecIoStage::LABELS[{i}] `{lb}` drifted from \
                 CompilerSpecIoStage::ALL[{i}].label() `{via_variant}` \
                 — the canonical declaration order of the two ALL \
                 arrays must match element-wise",
                lb = super::CompilerSpecIoStage::LABELS[i],
                via_variant = stage.label(),
            );
        }
    }

    #[test]
    fn compiler_spec_io_stage_labels_pairwise_distinct() {
        // PAIRWISE DISJOINTNESS: the four `&'static str` labels on
        // the disk-persistence stage-label algebra MUST differ so
        // any consumer that keys a hashmap / dispatch table on the
        // label bytes (`match label { "serialize" => ...,
        // "deserialize" => ..., ... }`) cannot route two variants
        // through the same arm. Family-wide sweep over LABELS ×
        // LABELS — supersedes any single per-pair assertion and
        // picks up new variants mechanically when the array grows.
        // Sibling posture to `kwarg_path_kind_labels_pairwise_distinct`
        // on the `KwargPathKind::LABELS` family.
        //
        // Note: unlike `KwargPathKind` / `ExpectedKwargShape`, the
        // parent enum keys `FromStr` on the compound
        // `"{operation}: {label}"` key rather than on `label` alone
        // (see `CompilerSpecIoStage::from_str`), so pairwise-distinct
        // labels are not a hard load-bearing invariant for the
        // FromStr sweep. But they ARE the load-bearing invariant for
        // every downstream consumer that keys on the label alone
        // (metric-label tables, LSP completion, `tatara-check` grep
        // budgets on the `{stage}:` prefix), and pinning the
        // property here catches a regression that collides two
        // variants on their singular label projection before those
        // consumer sites drift.
        for (i, a) in super::CompilerSpecIoStage::LABELS.iter().enumerate() {
            for (j, b) in super::CompilerSpecIoStage::LABELS.iter().enumerate() {
                if i == j {
                    continue;
                }
                assert_ne!(
                    a, b,
                    "CompilerSpecIoStage::LABELS[{i}] `{a}` collides \
                     with CompilerSpecIoStage::LABELS[{j}] `{b}` — \
                     the singular label projection is no longer a \
                     bijection with ALL, breaking every consumer that \
                     keys on the label alone"
                );
            }
        }
    }

    #[test]
    fn compiler_spec_io_stage_operation_method_routes_through_typed_constants() {
        // PATH-UNIFORMITY: the inherent `Self::operation(self)` method
        // MUST return the per-role `pub const` byte-for-byte for
        // each reachable variant. A regression that reverts ONE arm
        // to an inline `"realize_to_disk"` string literal (e.g. a
        // merge-conflict resolution that picked the pre-lift form)
        // silently reintroduces the ≥2 PRIME-DIRECTIVE trigger the
        // lift resolved — this test catches that by pinning each
        // arm's return value to the constant, so the two paths
        // (inline vs. typed constant) cannot both hold. Sibling
        // posture to
        // `compiler_spec_io_stage_label_method_routes_through_typed_constants`
        // on the paired stage-label algebra.
        assert_eq!(
            super::CompilerSpecIoStage::RealizeToDiskSerialize.operation(),
            super::CompilerSpecIoStage::REALIZE_TO_DISK_OPERATION,
            "CompilerSpecIoStage::RealizeToDiskSerialize.operation() \
             drifted from CompilerSpecIoStage::\
             REALIZE_TO_DISK_OPERATION — the match arm reverted to an \
             inline literal"
        );
        assert_eq!(
            super::CompilerSpecIoStage::RealizeToDiskWrite.operation(),
            super::CompilerSpecIoStage::REALIZE_TO_DISK_OPERATION,
            "CompilerSpecIoStage::RealizeToDiskWrite.operation() \
             drifted from CompilerSpecIoStage::\
             REALIZE_TO_DISK_OPERATION — the match arm reverted to an \
             inline literal"
        );
        assert_eq!(
            super::CompilerSpecIoStage::LoadFromDiskRead.operation(),
            super::CompilerSpecIoStage::LOAD_FROM_DISK_OPERATION,
            "CompilerSpecIoStage::LoadFromDiskRead.operation() drifted \
             from CompilerSpecIoStage::LOAD_FROM_DISK_OPERATION — the \
             match arm reverted to an inline literal"
        );
        assert_eq!(
            super::CompilerSpecIoStage::LoadFromDiskDeserialize.operation(),
            super::CompilerSpecIoStage::LOAD_FROM_DISK_OPERATION,
            "CompilerSpecIoStage::LoadFromDiskDeserialize.operation() \
             drifted from CompilerSpecIoStage::LOAD_FROM_DISK_OPERATION \
             — the match arm reverted to an inline literal"
        );
    }

    #[test]
    fn compiler_spec_io_stage_operations_has_expected_cardinality() {
        // Cardinality contract: `Self::OPERATIONS.len() == 4` —
        // pinned at the declaration site by rustc's forced-arity
        // check on `[&'static str; 4]`. This test surfaces the arity
        // as a fail-loud runtime pin so a future refactor that
        // switches the array type to `&[&'static str]` (dropping the
        // compile-time arity forcing) doesn't silently loosen the
        // closed-set discipline the family relies on. Sibling posture
        // to `compiler_spec_io_stage_labels_has_expected_cardinality`
        // on the paired stage-label algebra.
        assert_eq!(
            super::CompilerSpecIoStage::OPERATIONS.len(),
            4,
            "CompilerSpecIoStage::OPERATIONS cardinality drifted from \
             4 — the disk-persistence operation-label closed set \
             gained or lost a variant without the ALL / OPERATIONS \
             pair being updated in tandem"
        );
    }

    #[test]
    fn compiler_spec_io_stage_operations_align_with_all_by_index() {
        // ALIGNMENT CONTRACT: `Self::OPERATIONS[i] ==
        // Self::ALL[i].operation()` element-wise. The two ALL arrays
        // (typed variants, canonical `&'static str` operation labels)
        // share ONE canonical declaration order — a regression that
        // reorders ONE array without reordering the other silently
        // misaligns every `zip(Self::ALL, Self::OPERATIONS)` consumer
        // (LSP completion providers keyed on the operation slot,
        // metric-label emitters, coverage reporters that walk the
        // operation × stage compound-key surface). Pinning by-index
        // alignment here catches the reorder at test time. Sibling
        // posture to `compiler_spec_io_stage_labels_align_with_all_by_index`
        // on the paired stage-label algebra.
        assert_eq!(
            super::CompilerSpecIoStage::OPERATIONS.len(),
            super::CompilerSpecIoStage::ALL.len(),
            "CompilerSpecIoStage::OPERATIONS and \
             CompilerSpecIoStage::ALL diverged in cardinality — the \
             per-role constants and enum variants must stay in \
             lockstep"
        );
        for (i, stage) in super::CompilerSpecIoStage::ALL.iter().enumerate() {
            assert_eq!(
                super::CompilerSpecIoStage::OPERATIONS[i],
                stage.operation(),
                "CompilerSpecIoStage::OPERATIONS[{i}] `{op}` drifted \
                 from CompilerSpecIoStage::ALL[{i}].operation() \
                 `{via_variant}` — the canonical declaration order \
                 of the two ALL arrays must match element-wise",
                op = super::CompilerSpecIoStage::OPERATIONS[i],
                via_variant = stage.operation(),
            );
        }
    }

    #[test]
    fn compiler_spec_io_stage_operations_partition_all_two_ways() {
        // TWO-WAY PARTITION CONTRACT: unlike `Self::LABELS` — whose
        // four elements are pairwise distinct because each `label()`
        // projection is bijective with its variant — `Self::OPERATIONS`
        // contains DUPLICATES by construction. The operation
        // projection bifurcates the closed set into exactly two
        // disjoint groups of two: `{RealizeToDiskSerialize,
        // RealizeToDiskWrite}` share `"realize_to_disk"` and
        // `{LoadFromDiskRead, LoadFromDiskDeserialize}` share
        // `"load_from_disk"`. The 2-of-2-to-2 shape is load-bearing
        // for the compound-key `"{operation}: {label}"` surface —
        // if the operation projection ever grew bijective with
        // `ALL` the compound key would collapse to `label`-only and
        // the parse boundary would silently accept unreachable
        // cross-product pairs. Pin the exact multiplicities here so
        // a future refactor that (a) adds a distinct per-variant
        // operation, or (b) collapses the two operations into one
        // shared string, fails-loudly. Sibling posture to
        // `compiler_spec_io_stage_labels_pairwise_distinct` on the
        // paired stage-label algebra — where LABELS pins
        // distinctness, OPERATIONS pins the exact two-way partition
        // multiplicity.
        let realize_count = super::CompilerSpecIoStage::OPERATIONS
            .iter()
            .filter(|&&op| op == super::CompilerSpecIoStage::REALIZE_TO_DISK_OPERATION)
            .count();
        let load_count = super::CompilerSpecIoStage::OPERATIONS
            .iter()
            .filter(|&&op| op == super::CompilerSpecIoStage::LOAD_FROM_DISK_OPERATION)
            .count();
        assert_eq!(
            realize_count, 2,
            "CompilerSpecIoStage::OPERATIONS multiplicity of \
             REALIZE_TO_DISK_OPERATION drifted from 2 — the \
             realize-side bifurcation over {{serialize, write}} is \
             load-bearing for the compound-key surface"
        );
        assert_eq!(
            load_count, 2,
            "CompilerSpecIoStage::OPERATIONS multiplicity of \
             LOAD_FROM_DISK_OPERATION drifted from 2 — the load-side \
             bifurcation over {{read, deserialize}} is load-bearing \
             for the compound-key surface"
        );
        assert_eq!(
            realize_count + load_count,
            super::CompilerSpecIoStage::OPERATIONS.len(),
            "CompilerSpecIoStage::OPERATIONS gained an operation label \
             outside the two-way partition — the closed-set operation \
             axis is no longer a clean {{realize_to_disk ⊎ load_from_disk}} \
             bifurcation"
        );
        assert_ne!(
            super::CompilerSpecIoStage::REALIZE_TO_DISK_OPERATION,
            super::CompilerSpecIoStage::LOAD_FROM_DISK_OPERATION,
            "CompilerSpecIoStage::REALIZE_TO_DISK_OPERATION collided \
             with CompilerSpecIoStage::LOAD_FROM_DISK_OPERATION — the \
             two-way partition collapsed to one group, breaking every \
             compound-key `{{operation}}: {{label}}` round-trip"
        );
    }

