    #[test]
    fn expected_kwarg_shape_label_method_routes_through_typed_constants() {
        // PATH-UNIFORMITY: the inherent `Self::label(self)` method
        // MUST return the per-role `pub const` byte-for-byte for
        // each reachable variant. A regression that reverts ONE arm
        // to an inline `"number"` / `"list of strings"` string
        // literal (e.g. a merge-conflict resolution that picked the
        // pre-lift form) silently reintroduces the ≥2 PRIME-DIRECTIVE
        // trigger the lift resolved — this test catches that by
        // pinning the arm's return value to the constant, so the two
        // paths (inline vs. typed constant) cannot both hold.
        // Sibling posture to
        // `kwarg_path_kind_label_method_routes_through_typed_constants`.
        assert_eq!(
            ExpectedKwargShape::Keyword.label(),
            ExpectedKwargShape::KEYWORD_LABEL,
            "ExpectedKwargShape::Keyword.label() drifted from \
             ExpectedKwargShape::KEYWORD_LABEL — the match arm \
             reverted to an inline literal"
        );
        assert_eq!(
            ExpectedKwargShape::String.label(),
            ExpectedKwargShape::STRING_LABEL,
            "ExpectedKwargShape::String.label() drifted from \
             ExpectedKwargShape::STRING_LABEL — the match arm \
             reverted to an inline literal"
        );
        assert_eq!(
            ExpectedKwargShape::Int.label(),
            ExpectedKwargShape::INT_LABEL,
            "ExpectedKwargShape::Int.label() drifted from \
             ExpectedKwargShape::INT_LABEL — the match arm reverted \
             to an inline literal"
        );
        assert_eq!(
            ExpectedKwargShape::Number.label(),
            ExpectedKwargShape::NUMBER_LABEL,
            "ExpectedKwargShape::Number.label() drifted from \
             ExpectedKwargShape::NUMBER_LABEL — the match arm \
             reverted to an inline literal"
        );
        assert_eq!(
            ExpectedKwargShape::Bool.label(),
            ExpectedKwargShape::BOOL_LABEL,
            "ExpectedKwargShape::Bool.label() drifted from \
             ExpectedKwargShape::BOOL_LABEL — the match arm reverted \
             to an inline literal"
        );
        assert_eq!(
            ExpectedKwargShape::List.label(),
            ExpectedKwargShape::LIST_LABEL,
            "ExpectedKwargShape::List.label() drifted from \
             ExpectedKwargShape::LIST_LABEL — the match arm reverted \
             to an inline literal"
        );
        assert_eq!(
            ExpectedKwargShape::ListOfStrings.label(),
            ExpectedKwargShape::LIST_OF_STRINGS_LABEL,
            "ExpectedKwargShape::ListOfStrings.label() drifted from \
             ExpectedKwargShape::LIST_OF_STRINGS_LABEL — the match \
             arm reverted to an inline literal"
        );
    }

    #[test]
    fn expected_kwarg_shape_labels_has_expected_cardinality() {
        // Cardinality contract: `Self::LABELS.len() == 7` — pinned at
        // the declaration site by rustc's forced-arity check on
        // `[&'static str; 7]`. This test surfaces the arity as a
        // fail-loud runtime pin so a future refactor that switches
        // the array type to `&[&'static str]` (dropping the compile-
        // time arity forcing) doesn't silently loosen the closed-set
        // discipline the family relies on. Sibling posture to
        // `kwarg_path_kind_labels_has_expected_cardinality` on the
        // `KwargPathKind::LABELS` family.
        assert_eq!(
            ExpectedKwargShape::LABELS.len(),
            7,
            "ExpectedKwargShape::LABELS cardinality drifted from 7 \
             — the expected-shape closed set gained or lost a variant \
             without the ALL / LABELS pair being updated in tandem"
        );
    }

    #[test]
    fn expected_kwarg_shape_labels_align_with_all_by_index() {
        // ALIGNMENT CONTRACT: `Self::LABELS[i] ==
        // Self::ALL[i].label()` element-wise. The two ALL arrays
        // (typed variants, canonical `&'static str` labels) share
        // ONE canonical declaration order — a regression that
        // reorders ONE array without reordering the other silently
        // misaligns every `zip(Self::ALL, Self::LABELS)` consumer
        // (LSP completion providers, metric-label emitters, coverage
        // reporters). Pinning by-index alignment here catches the
        // reorder at test time. Sibling posture to
        // `kwarg_path_kind_labels_align_with_all_by_index`.
        assert_eq!(
            ExpectedKwargShape::LABELS.len(),
            ExpectedKwargShape::ALL.len(),
            "ExpectedKwargShape::LABELS and ExpectedKwargShape::ALL \
             diverged in cardinality — the per-role constants and \
             enum variants must stay in lockstep"
        );
        for (i, shape) in ExpectedKwargShape::ALL.iter().enumerate() {
            assert_eq!(
                ExpectedKwargShape::LABELS[i],
                shape.label(),
                "ExpectedKwargShape::LABELS[{i}] `{lb}` drifted from \
                 ExpectedKwargShape::ALL[{i}].label() `{via_variant}` \
                 — the canonical declaration order of the two ALL \
                 arrays must match element-wise",
                lb = ExpectedKwargShape::LABELS[i],
                via_variant = shape.label(),
            );
        }
    }

    #[test]
    fn expected_kwarg_shape_labels_pairwise_distinct() {
        // PAIRWISE DISJOINTNESS: the seven `&'static str` labels on
        // the expected-shape algebra MUST differ so the derive-
        // generated FromStr's linear sweep cannot route two variants
        // through the same arm. Family-wide sweep over LABELS ×
        // LABELS — supersedes any single per-pair assertion and picks
        // up new variants mechanically when the array grows. Sibling
        // posture to `kwarg_path_kind_labels_pairwise_distinct`.
        for (i, a) in ExpectedKwargShape::LABELS.iter().enumerate() {
            for (j, b) in ExpectedKwargShape::LABELS.iter().enumerate() {
                if i == j {
                    continue;
                }
                assert_ne!(
                    a, b,
                    "ExpectedKwargShape::LABELS[{i}] `{a}` collides \
                     with ExpectedKwargShape::LABELS[{j}] `{b}` — the \
                     derive-generated FromStr sweep would route two \
                     variants through the same arm"
                );
            }
        }
    }

    #[test]
    fn expected_kwarg_shape_labels_all_round_trip_through_from_str() {
        // Family-wide bidirection: every entry of `Self::LABELS` MUST
        // parse back to some `ExpectedKwargShape` variant AND that
        // variant's `label()` MUST equal the original entry. Sibling
        // posture to
        // `kwarg_path_kind_labels_all_round_trip_through_from_str`
        // (sweeps over `Self::ALL`); this test sweeps over the per-
        // role `&'static str` constants directly, catching a
        // regression where one of the seven constants drifts from
        // the corresponding `Self::label` arm (e.g.
        // `LIST_OF_STRINGS_LABEL` set to `"list-of-strings"` while
        // `Self::ListOfStrings.label()` still returns
        // `Self::LIST_OF_STRINGS_LABEL`, which would parse to
        // `ExpectedKwargShape::ListOfStrings` correctly but break
        // every downstream consumer that pinned the literal `"list of
        // strings"` bytes).
        for lb in ExpectedKwargShape::LABELS {
            let parsed: ExpectedKwargShape = lb.parse().unwrap_or_else(|_| {
                panic!(
                    "ExpectedKwargShape::LABELS entry `{lb}` failed to \
                     parse — the entry drifted from Self::label"
                )
            });
            assert_eq!(
                parsed.label(),
                lb,
                "ExpectedKwargShape::LABELS entry `{lb}` parses to a \
                 variant whose label() `{}` does not match — the \
                 constant and the match arm drifted apart",
                parsed.label(),
            );
        }
    }

    #[test]
    fn expected_kwarg_shape_labels_cover_sorted_closed_set() {
        // Family-wide sweep: `Self::LABELS`, projected through sort,
        // MUST equal the derive-generated `sorted_labels()` on the
        // `ClosedSet` trait. Catches a regression where a new
        // variant is added to `Self::ALL` + `Self::label` (so
        // `sorted_labels()` grows) but the maintainer forgets to
        // extend the parallel per-role `pub const` + `Self::LABELS`
        // pair. Distinct from `_align_with_all_by_index` (which pins
        // ORDER preservation) and `_pairwise_distinct` (which pins
        // WITHIN-array uniqueness): this pin cross-checks the LABELS
        // array against the derive-generated candidate-list on the
        // trait, so a partial extension where LABELS grows but ALL
        // doesn't (or vice-versa) surfaces at both this pin AND
        // `_align_with_all_by_index`.
        let mut sorted_labels: Vec<&'static str> = ExpectedKwargShape::LABELS.to_vec();
        sorted_labels.sort_unstable();
        assert_eq!(
            sorted_labels,
            <ExpectedKwargShape as crate::ClosedSet>::sorted_labels(),
            "ExpectedKwargShape::LABELS diverged from the derive-\
             generated `sorted_labels()` — a variant was added or \
             removed from one array without the other tracking"
        );
    }

    // ── SexpShape closed-set lift ───────────────────────────────────────
    //
    // The `LispError::TypeMismatch.got` and
    // `LispError::NamedFormNonSymbolName.got` slots were promoted from
    // `&'static str` to the typed closed-set `SexpShape` enum. The
    // twelve reachable Sexp outermost shapes — `Nil` / `Symbol` /
    // `Keyword` / `String` / `Int` / `Float` / `Bool` / `List` /
    // `Quote` / `Quasiquote` / `Unquote` / `UnquoteSplice` — are now
    // encoded as variant identities so authoring tools (REPL, LSP,
    // `tatara-check`) bind on `SexpShape::Int` etc. directly rather
    // than substring-matching `got == "int"`. Same posture as
    // `KwargPath`, `ExpectedKwargShape`, `MacroDefHead`, `UnquoteForm`,
    // `CompilerSpecIoStage`, and `TemplateInvariantKind`. After this
    // lift the `TypeMismatch` variant is fully closed-set typed in
    // ALL THREE of its slots — no `&'static str` projection remains
    // at any helper boundary.

    #[test]
    fn sexp_shape_label_renders_canonical_string_for_every_variant() {
        // Pin every variant's canonical `&'static str` projection — a
        // regression that drifts any label (typo in `"strin"` for
        // `"string"`, swap of `"int"` ↔ `"float"`, capitalization
        // drift `"Quote"` for `"quote"`) fails-loudly here. The twelve
        // labels are byte-for-byte identical to the pre-lift
        // `sexp_type_name` projection so existing
        // `format!("{err}").contains("got int")` /
        // `got string` / `got list` / etc. assertions in consumer
        // crates pass unchanged across the lift.
        assert_eq!(SexpShape::Nil.label(), "nil");
        assert_eq!(SexpShape::Symbol.label(), "symbol");
        assert_eq!(SexpShape::Keyword.label(), "keyword");
        assert_eq!(SexpShape::String.label(), "string");
        assert_eq!(SexpShape::Int.label(), "int");
        assert_eq!(SexpShape::Float.label(), "float");
        assert_eq!(SexpShape::Bool.label(), "bool");
        assert_eq!(SexpShape::List.label(), "list");
        assert_eq!(SexpShape::Quote.label(), "quote");
        assert_eq!(SexpShape::Quasiquote.label(), "quasiquote");
        assert_eq!(SexpShape::Unquote.label(), "unquote");
        assert_eq!(SexpShape::UnquoteSplice.label(), "unquote-splice");
    }

    #[test]
    fn sexp_shape_display_matches_label_for_every_variant() {
        // Pin Display-equals-label: the `#[error("... got {got}")]`
        // annotations on `LispError::TypeMismatch` and
        // `LispError::NamedFormNonSymbolName` project through Display,
        // and Display delegates to `label()`. A regression that
        // introduces a Display impl that deviates from `label()`
        // (e.g. capitalizing one variant) would drift the diagnostic
        // surface; this test pins the contract.
        assert_eq!(format!("{}", SexpShape::Nil), "nil");
        assert_eq!(format!("{}", SexpShape::Symbol), "symbol");
        assert_eq!(format!("{}", SexpShape::Keyword), "keyword");
        assert_eq!(format!("{}", SexpShape::String), "string");
        assert_eq!(format!("{}", SexpShape::Int), "int");
        assert_eq!(format!("{}", SexpShape::Float), "float");
        assert_eq!(format!("{}", SexpShape::Bool), "bool");
        assert_eq!(format!("{}", SexpShape::List), "list");
        assert_eq!(format!("{}", SexpShape::Quote), "quote");
        assert_eq!(format!("{}", SexpShape::Quasiquote), "quasiquote");
        assert_eq!(format!("{}", SexpShape::Unquote), "unquote");
        assert_eq!(format!("{}", SexpShape::UnquoteSplice), "unquote-splice");
    }

    #[test]
    fn sexp_shape_label_routes_through_typed_per_variant_constants() {
        // PATH-UNIFORMITY: `SexpShape::label(v)` MUST equal the per-role
        // `pub const V_LABEL` for every `v`. Pre-lift the twelve arms
        // held inline `&'static str` literals; post-lift each arm binds
        // to its per-role constant. A regression that reverts ANY arm
        // to an inline literal (e.g. `Self::Symbol => "symbol"`) still
        // renders identically at runtime but silently disagrees with
        // the typed source of truth — this pin closes that drift.
        assert_eq!(SexpShape::Nil.label(), SexpShape::NIL_LABEL);
        assert_eq!(SexpShape::Symbol.label(), SexpShape::SYMBOL_LABEL);
        assert_eq!(SexpShape::Keyword.label(), SexpShape::KEYWORD_LABEL);
        assert_eq!(SexpShape::String.label(), SexpShape::STRING_LABEL);
        assert_eq!(SexpShape::Int.label(), SexpShape::INT_LABEL);
        assert_eq!(SexpShape::Float.label(), SexpShape::FLOAT_LABEL);
        assert_eq!(SexpShape::Bool.label(), SexpShape::BOOL_LABEL);
        assert_eq!(SexpShape::List.label(), SexpShape::LIST_LABEL);
        assert_eq!(SexpShape::Quote.label(), SexpShape::QUOTE_LABEL);
        assert_eq!(SexpShape::Quasiquote.label(), SexpShape::QUASIQUOTE_LABEL);
        assert_eq!(SexpShape::Unquote.label(), SexpShape::UNQUOTE_LABEL);
        assert_eq!(
            SexpShape::UnquoteSplice.label(),
            SexpShape::UNQUOTE_SPLICE_LABEL
        );
    }

    #[test]
    fn sexp_shape_labels_has_expected_cardinality() {
        // Cardinality contract: `Self::LABELS.len() == 12` — the closed
        // set of Sexp outermost shapes has EXACTLY twelve members. A
        // regression that loosens the type to `&[&'static str]` fails
        // HERE, as does a refactor that adds a thirteenth variant to
        // ALL without adding its label to LABELS (rustc's forced-arity
        // check on `[&'static str; 12]` fails compilation).
        assert_eq!(
            SexpShape::LABELS.len(),
            12,
            "SexpShape::LABELS cardinality drifted from 12 — the twelve \
             reachable Sexp outermost shapes were extended without \
             extending the LABELS array in lockstep"
        );
        assert_eq!(SexpShape::LABELS.len(), SexpShape::ALL.len(),);
    }

    #[test]
    fn sexp_shape_labels_align_with_all_by_index() {
        // ALIGNMENT CONTRACT: `Self::LABELS[i] == Self::ALL[i].label()`
        // element-wise. Binds the closed-set outer algebra's ordering
        // to the per-role LABEL constant ordering so any
        // `zip(SexpShape::ALL, SexpShape::LABELS)` consumer (LSP
        // completion, `tatara-check` coverage sweep, Sekiban metric-
        // label emitter) reads a coherent (variant, label) pair off
        // ONE forced-arity array pair rather than through a per-
        // consumer paired-iteration convention.
        for (i, v) in SexpShape::ALL.iter().enumerate() {
            assert_eq!(
                SexpShape::LABELS[i],
                v.label(),
                "SexpShape::LABELS[{i}] `{kw}` drifted from \
                 SexpShape::ALL[{i}].label() `{via_variant}` — the \
                 canonical ALL ordering and the LABELS ordering must \
                 match element-wise",
                kw = SexpShape::LABELS[i],
                via_variant = v.label(),
            );
        }
    }

    #[test]
    fn sexp_shape_labels_pairwise_distinct() {
        // Pairwise disjointness contract: every distinct pair of rows
        // in `Self::LABELS` MUST be byte-distinct. A collision would
        // silently degrade a `TypeMismatch { got: SexpShape::Int, ... }`
        // and a `TypeMismatch { got: SexpShape::Float, ... }` to
        // identically-rendered diagnostics, defeating the closed-set
        // typed-slot promotion. Twelve labels × twelve rows sweeps
        // `LABELS × LABELS` — supersedes any single collision pin.
        for (i, a) in SexpShape::LABELS.iter().enumerate() {
            for (j, b) in SexpShape::LABELS.iter().enumerate() {
                if i == j {
                    continue;
                }
                assert_ne!(
                    a, b,
                    "SexpShape::LABELS[{i}] `{a}` collides with \
                     SexpShape::LABELS[{j}] `{b}` — the diagnostic \
                     label surface must be pairwise byte-distinct across \
                     the twelve reachable Sexp outermost shapes"
                );
            }
        }
    }

    #[test]
    fn sexp_shape_atom_carving_labels_align_with_expected_kwarg_shape_labels() {
        // CROSS-AXIS IDENTITY: the SexpShape's atomic-payload carving
        // ({Symbol, Keyword, String, Int, Bool, List}) shares FIVE
        // label-bytes byte-for-byte with ExpectedKwargShape's
        // corresponding per-role constants — the ExpectedKwargShape
        // docstrings on `KEYWORD_LABEL`, `STRING_LABEL`, `INT_LABEL`,
        // `BOOL_LABEL`, `LIST_LABEL` already anticipate this identity
        // ("matches `SexpShape::X_LABEL` byte-for-byte"). Post-lift the
        // identity is a compile-time cross-const composition pin
        // rather than a per-consumer byte-string convention.
        //
        // The overlap is intentional and load-bearing: consumer
        // diagnostic strings like `"expected keyword, got keyword"`
        // reuse the SAME byte-string on both sides of the got/expected
        // gate, so a spelling migration on ONE axis without the OTHER
        // would introduce a silent diagnostic asymmetry. Pinned here.
        assert_eq!(SexpShape::KEYWORD_LABEL, ExpectedKwargShape::KEYWORD_LABEL);
        assert_eq!(SexpShape::STRING_LABEL, ExpectedKwargShape::STRING_LABEL);
        assert_eq!(SexpShape::INT_LABEL, ExpectedKwargShape::INT_LABEL);
        assert_eq!(SexpShape::BOOL_LABEL, ExpectedKwargShape::BOOL_LABEL);
        assert_eq!(SexpShape::LIST_LABEL, ExpectedKwargShape::LIST_LABEL);
        // Non-overlapping bytes on the sibling axes: SexpShape::Float
        // ("float") is the narrower element-type; ExpectedKwargShape's
        // NUMBER_LABEL ("number") is the wider numeric-union label the
        // `extract_float` gate emits. The pair is intentionally
        // distinct — pin it so a naive rename doesn't collapse them.
        assert_ne!(SexpShape::FLOAT_LABEL, ExpectedKwargShape::NUMBER_LABEL);
    }

    #[test]
    fn expected_kwarg_shape_per_role_labels_alias_sexp_shape_per_role_labels_via_static_ptr() {
        // ALIAS-CHAIN ROUTING CONTRACT: the FIVE per-role
        // `pub const ExpectedKwargShape::X_LABEL` constants that share
        // vocabulary with a matching `SexpShape` carving arm MUST route
        // through the parent-superset's `pub const SexpShape::X_LABEL`
        // as a compile-time typed alias
        // (`pub const ExpectedKwargShape::X_LABEL: &'static str =
        // SexpShape::X_LABEL`) rather than as two independent inline
        // string literals whose bytes happen to agree — the byte-
        // equality contract is anchored one test up at
        // `sexp_shape_atom_carving_labels_align_with_expected_kwarg_shape_labels`;
        // THIS pin catches a regression that re-inlines ONE per-role
        // ExpectedKwargShape constant to a fresh literal even when the
        // rendered bytes still agree (because a distinct inline
        // literal lives at a different `&'static str` address inside
        // the rodata segment, while a `pub const` aliased through
        // `SexpShape::X_LABEL` MUST point at the SAME rodata address
        // as the parent superset's constant).
        //
        // Sibling-shape pin to the four prior-run alias-chain routing
        // pins on the UnquoteForm ⊂ QuoteForm 2-of-4 subset carving
        // (`unquote_form_marker_routes_through_to_quote_form_prefix_via_composition`,
        // `unquote_form_label_routes_through_to_quote_form_label_via_composition`,
        // `unquote_form_iac_forge_tag_routes_through_to_quote_form_iac_forge_tag_via_composition`,
        // `unquote_form_hash_discriminator_routes_through_to_quote_form_hash_discriminator_via_composition`)
        // — those pin the substitution-subset composition through the
        // superset via runtime pointer-equality on a value-carrying
        // method; THIS pin pins the ExpectedKwargShape ⊂ SexpShape
        // 5-of-7 subset carving's alias-chain through the parent-
        // superset via compile-time `pub const` identity on a
        // vocabulary-carrying constant.
        //
        // The TWO non-overlapping ExpectedKwargShape arms
        // (`NUMBER_LABEL` and `LIST_OF_STRINGS_LABEL`) stay OUTSIDE
        // this pin's sweep — those are direct-literal constants with
        // no [`SexpShape`] peer to alias through.
        //
        // Theory anchor: THEORY.md §II.1 invariant 5 (composition
        // preserves proofs) — the alias-chain composition law
        // `ExpectedKwargShape::X_LABEL == SexpShape::X_LABEL` on the
        // 5-of-7 subset carving is a rustc-time typed identity, not a
        // runtime byte-equality convention.
        assert!(
            std::ptr::eq(
                ExpectedKwargShape::KEYWORD_LABEL.as_ptr(),
                SexpShape::KEYWORD_LABEL.as_ptr(),
            ),
            "ExpectedKwargShape::KEYWORD_LABEL and SexpShape::KEYWORD_LABEL disagree on `&'static str` rodata address — the alias chain has been broken by an inline-literal re-derivation on the ExpectedKwargShape side",
        );
        assert!(
            std::ptr::eq(
                ExpectedKwargShape::STRING_LABEL.as_ptr(),
                SexpShape::STRING_LABEL.as_ptr(),
            ),
            "ExpectedKwargShape::STRING_LABEL and SexpShape::STRING_LABEL disagree on `&'static str` rodata address — the alias chain has been broken by an inline-literal re-derivation on the ExpectedKwargShape side",
        );
        assert!(
            std::ptr::eq(
                ExpectedKwargShape::INT_LABEL.as_ptr(),
                SexpShape::INT_LABEL.as_ptr(),
            ),
            "ExpectedKwargShape::INT_LABEL and SexpShape::INT_LABEL disagree on `&'static str` rodata address — the alias chain has been broken by an inline-literal re-derivation on the ExpectedKwargShape side",
        );
        assert!(
            std::ptr::eq(
                ExpectedKwargShape::BOOL_LABEL.as_ptr(),
                SexpShape::BOOL_LABEL.as_ptr(),
            ),
            "ExpectedKwargShape::BOOL_LABEL and SexpShape::BOOL_LABEL disagree on `&'static str` rodata address — the alias chain has been broken by an inline-literal re-derivation on the ExpectedKwargShape side",
        );
        assert!(
            std::ptr::eq(
                ExpectedKwargShape::LIST_LABEL.as_ptr(),
                SexpShape::LIST_LABEL.as_ptr(),
            ),
            "ExpectedKwargShape::LIST_LABEL and SexpShape::LIST_LABEL disagree on `&'static str` rodata address — the alias chain has been broken by an inline-literal re-derivation on the ExpectedKwargShape side",
        );
    }

    #[test]
    fn expected_kwarg_shape_residual_labels_lie_outside_sexp_shape_label_vocabulary() {
        // RESIDUAL-CARVING DISJOINTNESS CONTRACT: the TWO
        // ExpectedKwargShape arms that lie OUTSIDE the 5-of-7 aliased
        // subset carving (`NUMBER_LABEL`, `LIST_OF_STRINGS_LABEL`)
        // MUST carry vocabulary distinct from EVERY per-role
        // `SexpShape::X_LABEL` constant — otherwise the 5-of-7
        // carving would fail its subset-and-residual invariant (the
        // subset would carry MORE than 5 aliasable arms, or the
        // residual would carry FEWER than 2 direct-literal arms). The
        // pre-existing pin
        // `sexp_shape_atom_carving_labels_align_with_expected_kwarg_shape_labels`
        // anchors ONE of the two disjointness edges (SexpShape::FLOAT
        // vs ExpectedKwargShape::NUMBER); THIS pin anchors the
        // whole-family disjointness of both residual arms against
        // every SexpShape label at once.
        //
        // A regression that adds `SexpShape::Number` as a new variant
        // (renaming Float to Number) would fail HERE by making
        // `ExpectedKwargShape::NUMBER_LABEL` collide with the newly
        // added `SexpShape::NUMBER_LABEL`; the 5-of-7 carving MUST be
        // re-derived to 6-of-7 in that case (aliasing NUMBER_LABEL
        // through the new SexpShape arm). The pin surfaces the
        // structural-partition-change requirement at the disjointness
        // gate rather than through a silent literal-duplication.
        for &shape in SexpShape::ALL.iter() {
            let via_shape = SexpShape::label(shape);
            assert_ne!(
                ExpectedKwargShape::NUMBER_LABEL,
                via_shape,
                "ExpectedKwargShape::NUMBER_LABEL `\"number\"` collides with SexpShape::{shape:?}.label() `{via_shape}` — the 5-of-7 aliased subset carving's residual arm {{NUMBER}} MUST lie outside every SexpShape label; a collision means the carving needs to be re-derived to a 6-of-7 subset aliased through the newly-overlapping SexpShape arm",
            );
            assert_ne!(
                ExpectedKwargShape::LIST_OF_STRINGS_LABEL,
                via_shape,
                "ExpectedKwargShape::LIST_OF_STRINGS_LABEL `\"list of strings\"` collides with SexpShape::{shape:?}.label() `{via_shape}` — the 5-of-7 aliased subset carving's residual arm {{LIST_OF_STRINGS}} MUST lie outside every SexpShape label",
            );
        }
    }

    #[test]
    fn sexp_shape_quote_carving_labels_align_with_quote_form_iac_forge_tags() {
        // CROSS-AXIS IDENTITY: SexpShape's quote-family carving
        // ({Quote, Quasiquote, Unquote}) shares THREE label-bytes
        // byte-for-byte with QuoteForm's corresponding iac-forge tag
        // constants. Post-lift the identity is a compile-time cross-
        // const composition pin rather than a per-consumer convention.
        //
        // The UnquoteSplice variant is the ONE intentional exception:
        // SexpShape::UNQUOTE_SPLICE_LABEL is `"unquote-splice"` (short
        // form used in `LispError::TypeMismatch` diagnostic Display)
        // while QuoteForm::UNQUOTE_SPLICE_IAC_FORGE_TAG is
        // `"unquote-splicing"` (long form used for cross-crate byte-
        // identical interoperability with the iac-forge canonical
        // form). The asymmetry is documented in the per-role constant's
        // docstring and pinned in
        // `sexp_shape_unquote_splice_label_differs_from_quote_form_iac_forge_tag`.
        assert_eq!(
            SexpShape::QUOTE_LABEL,
            crate::ast::QuoteForm::QUOTE_IAC_FORGE_TAG
        );
        assert_eq!(
            SexpShape::QUASIQUOTE_LABEL,
            crate::ast::QuoteForm::QUASIQUOTE_IAC_FORGE_TAG
        );
        assert_eq!(
            SexpShape::UNQUOTE_LABEL,
            crate::ast::QuoteForm::UNQUOTE_IAC_FORGE_TAG
        );
    }

    #[test]
    fn sexp_shape_unquote_splice_label_differs_from_quote_form_iac_forge_tag() {
        // ONE intentional cross-axis asymmetry: SexpShape's diagnostic
        // label surface uses the SHORTER `"unquote-splice"` bytes while
        // QuoteForm's iac-forge canonical-form tag surface uses the
        // LONGER `"unquote-splicing"` bytes. Pin the asymmetry so a
        // naive rename on either surface doesn't collapse the two
        // sibling label vocabularies onto ONE spelling.
        assert_ne!(
            SexpShape::UNQUOTE_SPLICE_LABEL,
            crate::ast::QuoteForm::UNQUOTE_SPLICE_IAC_FORGE_TAG,
            "SexpShape::UNQUOTE_SPLICE_LABEL and \
             QuoteForm::UNQUOTE_SPLICE_IAC_FORGE_TAG collapsed to ONE \
             spelling — the two sibling label surfaces must render \
             distinct bytes so the UnquoteSplice diagnostic renders \
             the short `\"unquote-splice\"` bytes while iac-forge \
             canonical-form emits the long `\"unquote-splicing\"` bytes"
        );
        assert_eq!(SexpShape::UNQUOTE_SPLICE_LABEL, "unquote-splice");
        assert_eq!(
            crate::ast::QuoteForm::UNQUOTE_SPLICE_IAC_FORGE_TAG,
            "unquote-splicing"
        );
    }

    #[test]
    fn type_mismatch_got_carries_typed_shape_through_variant_slot() {
        // After the typed-slot promotion, `LispError::TypeMismatch.got`
        // is `SexpShape` — the closed-set typed enum. Consumers
        // (REPL, LSP, `tatara-check`) pattern-match on the variant
        // identity `SexpShape::Int` directly rather than
        // substring-matching a rendered `"got int"` prefix. Pin the
        // structural binding AND the Display projection so the
        // byte-for-byte rendering contract is anchored from both
        // angles. A regression that re-introduces a `&'static str`-
        // shaped `got` slot (collapsing the typed enum back into a
        // free-form label) fails-loudly here.
        let err = LispError::TypeMismatch {
            form: KwargPath::named("threshold"),
            expected: ExpectedKwargShape::Number,
            got: SexpShape::String,
        };
        match &err {
            LispError::TypeMismatch { got, .. } => {
                assert_eq!(*got, SexpShape::String);
            }
            other => panic!("expected TypeMismatch, got {other:?}"),
        }
        assert_eq!(
            format!("{err}"),
            "compile error in :threshold: expected number, got string"
        );
    }

    #[test]
    fn named_form_non_symbol_name_got_carries_typed_shape_through_variant_slot() {
        // Sibling pin to `type_mismatch_got_…` on the second `got`
        // slot that flows from `sexp_shape`. Both
        // `LispError::TypeMismatch.got` and
        // `LispError::NamedFormNonSymbolName.got` are typed
        // `SexpShape` now — one helper (`crate::domain::sexp_shape`)
        // is the single projection source, and rustc-enforces
        // matching at every projection site. A regression that
        // bifurcates the two slots (e.g. typed `SexpShape` on one,
        // `&'static str` on the other) fails-loudly here.
        let err = LispError::NamedFormNonSymbolName {
            keyword: "defpoint",
            got: SexpShape::List,
        };
        match &err {
            LispError::NamedFormNonSymbolName { got, .. } => {
                assert_eq!(*got, SexpShape::List);
            }
            other => panic!("expected NamedFormNonSymbolName, got {other:?}"),
        }
        assert_eq!(
            format!("{err}"),
            "compile error in defpoint: positional NAME must be a symbol or string (got list)"
        );
    }

    #[test]
    fn sexp_shape_all_is_unique_and_complete() {
        // Closed-set posture: `ALL` enumerates every reachable variant
        // EXACTLY ONCE — no duplicates, no omissions. The `[Self; 12]`
        // array literal in the declaration forces the arity at compile
        // time; this test catches the orthogonal failure modes — a
        // future variant added at the type without being added to ALL
        // (silently dropped from every consumer's sweep), or a typo
        // that duplicates an entry (silently double-counted). Same
        // truth-table pinning every sibling closed-set lift in the
        // workspace uses (RequestorKind::ALL, ReceiptKind::ALL,
        // ConditionKind::ALL, ProcessPhase::ALL, ChannelKind::ALL, …).
        //
        // The `iter+map+collect+sort_unstable` quadruple this test
        // inlined pre-lift now binds at `<SexpShape as
        // ClosedSet>::sorted_labels()` — the canonical-ordered
        // candidate-list projection on the trait. Distinctness of the
        // sorted result is covered by
        // `assert_closed_set_well_formed::<SexpShape>()`.
        assert_eq!(SexpShape::ALL.len(), 12);
        assert_eq!(
            <SexpShape as crate::ClosedSet>::sorted_labels(),
            vec![
                "bool",
                "float",
                "int",
                "keyword",
                "list",
                "nil",
                "quasiquote",
                "quote",
                "string",
                "symbol",
                "unquote",
                "unquote-splice",
            ],
            "SexpShape::ALL must cover every reachable Sexp outermost shape"
        );
    }

    #[test]
    fn sexp_shape_label_round_trips_through_from_str() {
        // Bidirectional `label` ↔ `FromStr` contract: for every
        // variant in ALL, `shape.label().parse() == Ok(shape)`. A
        // regression that drifts the (variant, literal) pairing at
        // ONE arm of `label` (typo, capitalization drift) OR at the
        // `FromStr` decode body (off-by-one, missing variant in the
        // sweep) fails-loudly here. The canonical-literal site is
        // singular (`label`) so the round-trip is the only way the
        // typed surface and the rendered diagnostic literal can
        // drift apart — pinning it here means they cannot.
        for shape in SexpShape::ALL {
            let parsed: SexpShape = shape
                .label()
                .parse()
                .expect("every ALL variant's label must round-trip through FromStr");
            assert_eq!(
                parsed,
                shape,
                "FromStr({}) must round-trip to the same variant",
                shape.label()
            );
        }
    }

    #[test]
    fn unknown_sexp_shape_carries_offending_input_verbatim() {
        // Operator-facing diagnostic contract: the offending input
        // lands in the typed error verbatim — no normalization, no
        // case-folding, no truncation. Pin the exact `#[error(...)]`
        // rendering AND the typed `.0` field projection so a future
        // refactor that normalizes (e.g. `.to_lowercase()`) before
        // building the error or that drops the input fails-loudly
        // here. Symmetric to every sibling `Unknown*` carrier in the
        // workspace.
        let err: UnknownSexpShape = "Symbol".parse::<SexpShape>().expect_err(
            "capitalized `Symbol` must NOT decode — labels are byte-equal case-sensitive",
        );
        assert_eq!(err.0, "Symbol");
        assert_eq!(format!("{err}"), "unknown sexp shape: Symbol");

        let err: UnknownSexpShape = "number"
            .parse::<SexpShape>()
            .expect_err("`number` is ExpectedKwargShape's vocabulary, not SexpShape's");
        assert_eq!(err.0, "number");
        assert_eq!(format!("{err}"), "unknown sexp shape: number");

        let err: UnknownSexpShape = ""
            .parse::<SexpShape>()
            .expect_err("empty input must NOT decode to a SexpShape");
        assert_eq!(err.0, "");
        assert_eq!(format!("{err}"), "unknown sexp shape: ");
    }

    #[test]
    fn sexp_shape_from_str_accepts_only_canonical_labels() {
        // Cross-axis guard: `ExpectedKwargShape::label()`'s vocabulary
        // overlaps with `SexpShape::label()` on five of seven entries
        // (`keyword` / `string` / `int` / `bool` / `list`) and DOES
        // NOT overlap on two (`number` / `list of strings`). The
        // overlap is intentional — both axes are projections of the
        // same `Sexp` algebra at typed-entry gates — but the
        // non-overlap is the load-bearing part: a `FromStr` that
        // silently accepts `"number"` as a `SexpShape` would corrupt
        // the typed identity. Pin BOTH directions: the overlap
        // decodes successfully (and to the matching `SexpShape`
        // variant), the non-overlap rejects.
        assert_eq!("keyword".parse::<SexpShape>().unwrap(), SexpShape::Keyword);
        assert_eq!("string".parse::<SexpShape>().unwrap(), SexpShape::String);
        assert_eq!("int".parse::<SexpShape>().unwrap(), SexpShape::Int);
        assert_eq!("bool".parse::<SexpShape>().unwrap(), SexpShape::Bool);
        assert_eq!("list".parse::<SexpShape>().unwrap(), SexpShape::List);

        assert!("number".parse::<SexpShape>().is_err());
        assert!("list of strings".parse::<SexpShape>().is_err());

        // Sanity: every UnquoteForm marker literal (`,` / `,@` / etc.)
        // is also NOT a SexpShape label — the marker projection lives
        // on a different axis (the rendered punctuation) than the
        // shape label (the structural identity).
        assert!(",".parse::<SexpShape>().is_err());
        assert!(",@".parse::<SexpShape>().is_err());
    }

    #[test]
    fn sexp_shape_int_bifurcates_from_float_through_variant_slot() {
        // `Int` and `Float` are distinct typed variants — a regression
        // that collapses them into a single `Number` variant (which
        // would drop the bifurcation that `Sexp::Atom(Int(_))` and
        // `Sexp::Atom(Float(_))` already carry at the AST layer) is
        // caught here. The two render distinct rendered labels and
        // hold distinct variant identities.
        let int_err = LispError::TypeMismatch {
            form: KwargPath::named("count"),
            expected: ExpectedKwargShape::String,
            got: SexpShape::Int,
        };
        let float_err = LispError::TypeMismatch {
            form: KwargPath::named("ratio"),
            expected: ExpectedKwargShape::String,
            got: SexpShape::Float,
        };
        assert_eq!(
            format!("{int_err}"),
            "compile error in :count: expected string, got int"
        );
        assert_eq!(
            format!("{float_err}"),
            "compile error in :ratio: expected string, got float"
        );
        match (&int_err, &float_err) {
            (LispError::TypeMismatch { got: a, .. }, LispError::TypeMismatch { got: b, .. }) => {
                assert_ne!(a, b);
                assert_eq!(*a, SexpShape::Int);
                assert_eq!(*b, SexpShape::Float);
            }
            _ => panic!("both must be TypeMismatch"),
        }
    }

    // ── SexpShape ↔ AtomKind / QuoteForm: typed-shape lattice inverses ──
    //
    // The forward embed projections [`crate::ast::AtomKind::sexp_shape`]
    // (6→12) and [`crate::ast::QuoteForm::sexp_shape`] (4→12) have
    // existed for prior runs (commits 121bb60 + b15-ish); their dual
    // projections [`SexpShape::as_atom_kind`] (12→6, partial) and
    // [`SexpShape::as_quote_form`] (12→4, partial) close the
    // embed/project section on the typed-shape lattice. The
    // composition laws below pin the (embed, project) pair is an
    // `Iso(AtomKind, AtomShape ⊂ SexpShape)` AND
    // `Iso(QuoteForm, QuoteShape ⊂ SexpShape)` — every typed marker
    // round-trips through the embed, every shape pre-image recovers
    // the typed marker. Pre-lift the typed-shape lattice's two
    // forward embeds had no dual projection naming the inverse 6-of-
    // 12 + 4-of-12 carvings; post-lift the carvings live at ONE site
    // each on the [`SexpShape`] algebra so a regression that drifts
    // the inverse from the embed surfaces at the round-trip pin
    // instead of at every speculative LSP / REPL / `tatara-check` /
    // metrics consumer's per-carving inline `match`.

    #[test]
    fn as_atom_kind_projects_each_atom_shape_to_canonical_atom_kind_and_rejects_non_atom_shapes() {
        // Per-variant truth-table sweep across every `SexpShape::ALL`
        // entry — pins each variant's canonical mapping (atomic-payload
        // arms project to the matching `AtomKind`; `Nil` / `List` /
        // every quote-family arm project to `None`) byte-for-byte so a
        // regression that drifts ONE arm (e.g. swaps `Symbol →
        // AtomKind::Keyword`, drops `Bool`'s arm to `None`, accepts
        // `List` as `Some(AtomKind::Str)`) fails loudly. The full
        // `SexpShape::ALL` sweep doubles as exhaustiveness — adding a
        // hypothetical thirteenth variant (e.g. `Vector` for `#(...)`)
        // forces the test author to extend BOTH this sweep AND the
        // typed `match` body, with rustc enforcing the match arm's
        // presence and this sweep enforcing the (variant, projected
        // mapping) pairing's canonical-form.
        use crate::ast::AtomKind;
        for shape in SexpShape::ALL {
            let projected = shape.as_atom_kind();
            let expected = match shape {
                SexpShape::Symbol => Some(AtomKind::Symbol),
                SexpShape::Keyword => Some(AtomKind::Keyword),
                SexpShape::String => Some(AtomKind::Str),
                SexpShape::Int => Some(AtomKind::Int),
                SexpShape::Float => Some(AtomKind::Float),
                SexpShape::Bool => Some(AtomKind::Bool),
                SexpShape::Nil
                | SexpShape::List
                | SexpShape::Quote
                | SexpShape::Quasiquote
                | SexpShape::Unquote
                | SexpShape::UnquoteSplice => None,
            };
            assert_eq!(
                projected, expected,
                "SexpShape::{shape:?}.as_atom_kind() drifted from canonical mapping"
            );
        }
    }

    #[test]
    fn atom_kind_sexp_shape_round_trips_through_as_atom_kind() {
        // The embed/project section law on the atomic carving:
        // `AtomKind::sexp_shape(k).as_atom_kind() == Some(k)` for every
        // `k: AtomKind::ALL`. Pinning the round-trip for every variant
        // in the closed set proves the (embed, project) pair is an
        // `Iso(AtomKind, AtomShape ⊂ SexpShape)` — the section is total
        // on `AtomKind`'s carving. A regression that drifts EITHER
        // direction (an `AtomKind::sexp_shape` arm that mis-maps OR a
        // `SexpShape::as_atom_kind` arm that mis-inverts) fails here
        // without depending on any per-consumer call site. Same posture
        // as `unquote_form_marker_routes_through_to_quote_form_prefix_
        // via_composition`'s round-trip on the 2-of-4 quote-family
        // subset.
        use crate::ast::AtomKind;
        for kind in AtomKind::ALL {
            let shape = kind.sexp_shape();
            let recovered = shape.as_atom_kind();
            assert_eq!(
                recovered,
                Some(kind),
                "AtomKind::{kind:?} did NOT round-trip — sexp_shape().as_atom_kind() must recover the typed marker"
            );
        }
    }

    #[test]
    fn as_quote_form_projects_each_quote_shape_to_canonical_quote_form_and_rejects_non_quote_shapes(
    ) {
        // Per-variant truth-table sweep across every `SexpShape::ALL`
        // entry — pins each variant's canonical mapping (quote-family
        // arms project to the matching `QuoteForm`; `Nil` / `List` /
        // every atomic-payload arm project to `None`) byte-for-byte.
        // Sibling sweep to
        // `as_atom_kind_projects_each_atom_shape_to_canonical_atom_kind_and_rejects_non_atom_shapes`
        // on the quote-family axis.
        use crate::ast::QuoteForm;
        for shape in SexpShape::ALL {
            let projected = shape.as_quote_form();
            let expected = match shape {
                SexpShape::Quote => Some(QuoteForm::Quote),
                SexpShape::Quasiquote => Some(QuoteForm::Quasiquote),
                SexpShape::Unquote => Some(QuoteForm::Unquote),
                SexpShape::UnquoteSplice => Some(QuoteForm::UnquoteSplice),
                SexpShape::Nil
                | SexpShape::List
                | SexpShape::Symbol
                | SexpShape::Keyword
                | SexpShape::String
                | SexpShape::Int
                | SexpShape::Float
                | SexpShape::Bool => None,
            };
            assert_eq!(
                projected, expected,
                "SexpShape::{shape:?}.as_quote_form() drifted from canonical mapping"
            );
        }
    }

    #[test]
    fn quote_form_sexp_shape_round_trips_through_as_quote_form() {
        // The embed/project section law on the quote-family carving:
        // `QuoteForm::sexp_shape(qf).as_quote_form() == Some(qf)` for
        // every `qf: QuoteForm::ALL`. Proves the (embed, project) pair
        // is an `Iso(QuoteForm, QuoteShape ⊂ SexpShape)` — the section
        // is total on `QuoteForm`'s carving. Sibling round-trip to
        // `atom_kind_sexp_shape_round_trips_through_as_atom_kind` on
        // the quote-family axis.
        use crate::ast::QuoteForm;
        for qf in QuoteForm::ALL {
            let shape = qf.sexp_shape();
            let recovered = shape.as_quote_form();
            assert_eq!(
                recovered,
                Some(qf),
                "QuoteForm::{qf:?} did NOT round-trip — sexp_shape().as_quote_form() must recover the typed marker"
            );
        }
    }

    #[test]
    fn as_atom_kind_and_as_quote_form_partition_carvable_sexp_shape_variants() {
        // Disjointness invariant: for every variant in
        // `SexpShape::ALL`, AT MOST ONE of `as_atom_kind()` and
        // `as_quote_form()` returns `Some` — the typed-shape lattice's
        // two named carvings partition the carve-able SexpShape
        // variants. The two non-carved variants (`Nil`, `List`) project
        // to `None` through BOTH projections — the kernel of both
        // partial inverses. A regression that drifts the partition
        // (e.g. accepts `SexpShape::List` as an atom kind, or as a
        // quote form) fails here. Sibling to
        // `as_atom_kind_projects_each_atom_shape_to_canonical_atom_kind_and_rejects_non_atom_shapes`
        // and
        // `as_quote_form_projects_each_quote_shape_to_canonical_quote_form_and_rejects_non_quote_shapes`
        // — those pin the per-axis canonical mapping; this pins the
        // joint disjointness across both axes. The residual-side of the
        // partition (the two `Nil`/`List` variants) is now itself a
        // typed carving `StructuralKind` — pinned by
        // `sexp_shape_partition_is_total_across_atom_quote_structural_carvings`.
        for shape in SexpShape::ALL {
            let atom = shape.as_atom_kind().is_some();
            let quote = shape.as_quote_form().is_some();
            assert!(
                !(atom && quote),
                "SexpShape::{shape:?} projects as BOTH an atom kind AND a quote form — typed-shape carvings must be disjoint"
            );
            // Cross-axis closure: the only variants that project as
            // NEITHER are the structural-residual shapes (`Nil` and
            // `List`). Every other variant must be in exactly ONE of
            // the two named carvings — the substrate's typed-shape
            // lattice's structural completeness pin. Post-lift the
            // residual-side identity binds to the typed
            // `as_structural_kind()` projection rather than a runtime
            // `matches!(shape, SexpShape::Nil | SexpShape::List)`
            // predicate; the invariant lives at ONE closed-set match
            // on the outer algebra.
            let carved = atom || quote;
            let expected_carved = shape.as_structural_kind().is_none();
            assert_eq!(
                carved, expected_carved,
                "SexpShape::{shape:?} must be carved iff it does not project through as_structural_kind"
            );
        }
    }

    #[test]
    fn sexp_shape_partition_is_total_across_atom_quote_structural_carvings() {
        // Partition-total invariant across ALL THREE typed-shape
        // carvings — the (typed theorem, previously test assertion)
        // this lift makes structural. For every variant in
        // `SexpShape::ALL`, EXACTLY ONE of `as_atom_kind()`,
        // `as_quote_form()`, `as_structural_kind()` returns `Some(_)`.
        // Pre-lift the residual side lived at ONE inline
        // `!matches!(shape, SexpShape::Nil | SexpShape::List)`
        // assertion inside the carving-disjointness pin above (the
        // runtime witness the substrate maintained by test
        // discipline); post-lift the residual is a TYPED CARVING
        // binding at ONE typed-algebra method, and the partition-
        // total invariant across the three carvings becomes a TYPED
        // THEOREM the joint sweep here surfaces byte-for-byte.
        //
        // Cardinalities: 6 + 4 + 2 = 12 (atomic-payload + quote-family
        // + structural-residual = every SexpShape). A regression that
        // drifts the partition-membership of any variant across any
        // of the three carvings surfaces here.
        let mut atom_count = 0;
        let mut quote_count = 0;
        let mut structural_count = 0;
        for shape in SexpShape::ALL {
            let atom = shape.as_atom_kind().is_some();
            let quote = shape.as_quote_form().is_some();
            let structural = shape.as_structural_kind().is_some();
            let membership = usize::from(atom) + usize::from(quote) + usize::from(structural);
            assert_eq!(
                membership, 1,
                "SexpShape::{shape:?} lands in {membership} carvings — partition must land it in EXACTLY ONE of (as_atom_kind, as_quote_form, as_structural_kind)",
            );
            atom_count += usize::from(atom);
            quote_count += usize::from(quote);
            structural_count += usize::from(structural);
        }
        assert_eq!(
            atom_count, 6,
            "atomic-payload carving must cover EXACTLY 6 of SexpShape::ALL",
        );
        assert_eq!(
            quote_count, 4,
            "quote-family carving must cover EXACTLY 4 of SexpShape::ALL",
        );
        assert_eq!(
            structural_count, 2,
            "structural-residual carving must cover EXACTLY 2 of SexpShape::ALL",
        );
        assert_eq!(
            atom_count + quote_count + structural_count,
            SexpShape::ALL.len(),
            "the three carvings must partition SexpShape::ALL totally (6 + 4 + 2 = 12)",
        );
    }

    #[test]
    fn as_atom_kind_composes_with_sexp_shape_via_atom_kind_label_round_trip() {
        // Cross-projection composition law: for every atom kind, the
        // diagnostic label round-trips through both directions of the
        // embed/project pair AND `AtomKind::label`:
        // `AtomKind::ALL[i].label() == AtomKind::ALL[i].sexp_shape()
        // .as_atom_kind().expect("...").label()`. This pin proves the
        // typed-shape lattice's two carvings are not only structural
        // inverses but ALSO label-coherent — a regression that drifts
        // the (AtomKind variant, SexpShape variant) pairing while
        // preserving the projection's structural inverseness (e.g. a
        // future refactor that renames the variants in lockstep but
        // leaves the per-variant labels stale) surfaces here. The
        // label-coherence binds the diagnostic surface to the typed
        // algebra at BOTH layers.
        use crate::ast::AtomKind;
        for kind in AtomKind::ALL {
            let via_round_trip = kind
                .sexp_shape()
                .as_atom_kind()
                .expect("every AtomKind round-trips through the embed/project pair")
                .label();
            assert_eq!(
                via_round_trip,
                kind.label(),
                "AtomKind::{kind:?}.label() drifted from sexp_shape().as_atom_kind().label() — embed/project must preserve label coherence"
            );
        }
    }

    #[test]
    fn as_quote_form_composes_with_sexp_shape_via_quote_form_prefix_round_trip() {
        // Cross-projection composition law (quote-family sibling of
        // `as_atom_kind_composes_with_sexp_shape_via_atom_kind_label_round_trip`):
        // for every `qf: QuoteForm::ALL`,
        // `qf.prefix() == qf.sexp_shape().as_quote_form().expect("...").prefix()`.
        // Pins the (QuoteForm variant, SexpShape variant) pairing
        // round-trips through the embed/project pair AND preserves
        // each variant's canonical homoiconic-prefix punctuation
        // (`"'"` / `` "`" `` / `","` / `",@"`) — a regression that
        // drifts the round-trip OR drifts the prefix surfaces here.
        use crate::ast::QuoteForm;
        for qf in QuoteForm::ALL {
            let via_round_trip = qf
                .sexp_shape()
                .as_quote_form()
                .expect("every QuoteForm round-trips through the embed/project pair")
                .prefix();
            assert_eq!(
                via_round_trip,
                qf.prefix(),
                "QuoteForm::{qf:?}.prefix() drifted from sexp_shape().as_quote_form().prefix() — embed/project must preserve prefix coherence"
            );
        }
    }

    // ── UnquoteForm: ALL closure + FromStr round-trip ──────────────────
    //
    // `UnquoteForm` (the two template-marker syntactic forms `,` and
    // `,@`) joins the substrate's closed-set algebra family —
    // `SexpShape::ALL` + `FromStr`, `AtomKind::ALL` + `FromStr`,
    // `RequestorKind::ALL` + `FromStr`, etc. — by lifting the canonical
    // `&'static str` marker literal vocabulary onto ONE site
    // (`Self::marker` keyed by `Self::ALL`) the operator-facing decode
    // path inverts. Pre-lift the punctuation vocabulary lived ONLY
    // in `marker()`'s match arms; post-lift the SAME vocabulary
    // round-trips through `FromStr` keyed on the closed set, so the
    // typed surface and the rendered diagnostic literal cannot drift.
    // Same posture as `sexp_shape_label_round_trips_through_from_str`
    // / `atom_kind_label_round_trips_through_from_str`.

    #[test]
    fn unquote_form_all_is_unique_and_complete() {
        // Closed-set posture: `ALL` enumerates every reachable variant
        // EXACTLY ONCE — no duplicates, no omissions. The `[Self; 2]`
        // array literal in the declaration forces the arity at compile
        // time; this test catches the orthogonal failure modes — a
        // future variant added at the type without being added to ALL
        // (silently dropped from every consumer's sweep), or a typo
        // that duplicates an entry (silently double-counted). Same
        // truth-table pinning every sibling closed-set lift in the
        // workspace uses (SexpShape::ALL, AtomKind::ALL,
        // RequestorKind::ALL, ReceiptKind::ALL, ConditionKind::ALL, …).
        //
        // The `iter+map+collect+sort_unstable` quadruple this test
        // inlined pre-lift now binds at `<UnquoteForm as
        // ClosedSet>::sorted_labels()` — the canonical-ordered
        // candidate-list projection on the trait. Distinctness of the
        // sorted result is covered by
        // `assert_closed_set_well_formed::<UnquoteForm>()`.
        assert_eq!(UnquoteForm::ALL.len(), 2);
        assert_eq!(
            <UnquoteForm as crate::ClosedSet>::sorted_labels(),
            vec![",", ",@"],
            "UnquoteForm::ALL must cover both template-marker syntactic forms"
        );
    }

    #[test]
    fn unquote_form_marker_round_trips_through_from_str() {
        // Bidirectional `marker` ↔ `FromStr` contract: for every
        // variant in ALL, `form.marker().parse() == Ok(form)`. A
        // regression that drifts the (variant, literal) pairing at
        // ONE arm of `marker` (typo, `,,` instead of `,`, `, @` with
        // a stray space) OR at the `FromStr` decode body (off-by-one,
        // missing variant in the sweep) fails-loudly here. The
        // canonical-literal site is singular (`marker`) so the
        // round-trip is the only way the typed surface and the
        // rendered diagnostic literal can drift apart — pinning it
        // here means they cannot.
        for form in UnquoteForm::ALL {
            let parsed: UnquoteForm = form
                .marker()
                .parse()
                .expect("every ALL variant's marker must round-trip through FromStr");
            assert_eq!(
                parsed,
                form,
                "FromStr({}) must round-trip to the same variant",
                form.marker()
            );
        }
    }

    #[test]
    fn unknown_unquote_form_carries_offending_input_verbatim() {
        // Operator-facing diagnostic contract: the offending input
        // lands in the typed error verbatim — no normalization, no
        // truncation, no whitespace coercion. Pin the exact
        // `#[error(...)]` rendering AND the typed `.0` field
        // projection so a future refactor that normalizes (e.g.
        // `.trim()`) before building the error or that drops the
        // input fails-loudly here. Symmetric to every sibling
        // `Unknown*` carrier in the workspace
        // ([`UnknownSexpShape`], [`crate::ast::UnknownAtomKind`],
        // `tatara_process::allocation::UnknownRequestorKind`, …).
        let err: UnknownUnquoteForm = ",,"
            .parse::<UnquoteForm>()
            .expect_err("doubled comma `,,` is not a canonical template marker");
        assert_eq!(err.0, ",,");
        assert_eq!(format!("{err}"), "unknown unquote form: ,,");

        let err: UnknownUnquoteForm = ",@@"
            .parse::<UnquoteForm>()
            .expect_err("doubled-at `,@@` is not a canonical template marker");
        assert_eq!(err.0, ",@@");
        assert_eq!(format!("{err}"), "unknown unquote form: ,@@");

        let err: UnknownUnquoteForm = ""
            .parse::<UnquoteForm>()
            .expect_err("empty input must NOT decode to an UnquoteForm");
        assert_eq!(err.0, "");
        assert_eq!(format!("{err}"), "unknown unquote form: ");
    }

    #[test]
    fn unquote_form_from_str_rejects_sexp_shape_labels_on_template_marker_axis() {
        // Cross-axis guard: [`SexpShape`] projects the SAME two
        // `Sexp::Unquote` / `Sexp::UnquoteSplice` constructors as
        // [`UnquoteForm`] does, but onto a DIFFERENT vocabulary —
        // `"unquote"` / `"unquote-splice"` (structural-identity labels)
        // vs `","` / `",@"` (punctuation markers). The two axes share
        // the same closed-set cardinality (2) but their vocabularies
        // are intentionally disjoint. A `FromStr` that silently
        // accepted `"unquote"` as an `UnquoteForm` would corrupt the
        // typed identity at the diagnostic boundary. Pin BOTH
        // directions: the SAME punctuation labels (`,` / `,@`) decode
        // through [`UnquoteForm`] but NOT through [`SexpShape`]; the
        // SAME structural labels (`"unquote"` / `"unquote-splice"`)
        // decode through [`SexpShape`] but NOT through [`UnquoteForm`].
        // Anchors the cross-axis disjointness from BOTH sides so a
        // regression that conflates the two axes' vocabularies fails
        // here.
        assert_eq!(",".parse::<UnquoteForm>().unwrap(), UnquoteForm::Unquote);
        assert_eq!(",@".parse::<UnquoteForm>().unwrap(), UnquoteForm::Splice);

        // The structural-identity labels project the SAME variants on
        // the SexpShape axis but are NOT canonical UnquoteForm markers.
        assert!("unquote".parse::<UnquoteForm>().is_err());
        assert!("unquote-splice".parse::<UnquoteForm>().is_err());

        // Sibling homoiconic-prefix-wrapper markers (`'` for quote,
        // `` ` `` for quasiquote) belong to the WIDER QuoteForm
        // superset on the SAME punctuation axis — they MUST reject
        // here because UnquoteForm carves the 2-of-4 template-
        // substitution subset of QuoteForm's 4-prefix closed set.
        assert!("'".parse::<UnquoteForm>().is_err());
        assert!("`".parse::<UnquoteForm>().is_err());

        // Whitespace-padded markers are NOT canonical — the
        // round-trip must be exact byte-for-byte against `marker()`.
        assert!(" ,".parse::<UnquoteForm>().is_err());
        assert!(", ".parse::<UnquoteForm>().is_err());
        assert!(", @".parse::<UnquoteForm>().is_err());
    }

    #[test]
    fn unquote_form_to_quote_form_round_trips_through_as_unquote_form() {
        // Pin the 2-of-4 subset → superset projection as a typed
        // section of [`crate::ast::QuoteForm::as_unquote_form`]: for
        // every `uf: UnquoteForm`, `uf.to_quote_form().as_unquote_form()
        // == Some(uf)`. Closes the (UnquoteForm, QuoteForm) pairing as
        // a round-trip identity on the typed algebra — pre-lift the
        // pairing only lived in the existing
        // `unquote_form_marker_subset_decodes_through_quote_form_from_str`
        // cross-axis test (which round-tripped through the rendered
        // marker string + FromStr); post-lift the pairing rides the
        // typed projection directly so a future regression that drifts
        // the (UnquoteForm variant, QuoteForm variant) pairing
        // (e.g., a future arm that maps `UnquoteForm::Splice →
        // QuoteForm::Unquote`) fails this assertion without depending
        // on the FromStr decoder sitting between the two.
        use crate::ast::QuoteForm;
        for uf in UnquoteForm::ALL {
            assert_eq!(
                uf.to_quote_form().as_unquote_form(),
                Some(uf),
                "UnquoteForm::{uf:?} → QuoteForm via to_quote_form does not invert through QuoteForm::as_unquote_form — the 2-of-4 subset projection is no longer a section",
            );
        }

        // Per-arm pinning of the canonical mapping (the byte-for-byte
        // pairing the composition `marker == to_quote_form().prefix()`
        // depends on).
        assert_eq!(UnquoteForm::Unquote.to_quote_form(), QuoteForm::Unquote);
        assert_eq!(
            UnquoteForm::Splice.to_quote_form(),
            QuoteForm::UnquoteSplice
        );
    }

    #[test]
    fn unquote_form_marker_routes_through_to_quote_form_prefix_via_composition() {
        // Post-lift composition pin: for every `uf: UnquoteForm`,
        // `uf.marker()` and `uf.to_quote_form().prefix()` agree on
        // BOTH axes — (a) byte equality (the rendered diagnostic
        // literal cannot drift between the two projections); (b)
        // pointer equality (the canonical `&'static str` literal lives
        // at ONE site — `QuoteForm::prefix`'s Unquote/UnquoteSplice
        // arms in `ast.rs` — and `UnquoteForm::marker` routes through
        // that ONE address via the typed composition).
        //
        // The pointer-equality axis is load-bearing: a regression that
        // re-inlines the literals at `UnquoteForm::marker` as a
        // parallel match-table fails the pointer pin even when the
        // rendered bytes still agree (the inline-literal-table copy
        // lives at a different `&'static str` address — rustc may
        // de-duplicate identical literals within a single Rust
        // compilation unit, but the contract this test pins is
        // routing-through-the-canonical-site, not deduplication-by-the-
        // optimizer; a future build flag that disables literal dedup
        // would unmask the regression that the bytes-only assertion
        // misses). Sibling-shape pin to commit 1db697f's
        // `atom_kind_label_routes_through_sexp_shape_label_via_sexp_shape_projection`
        // — both pin the subset's projection through the superset's
        // canonical site via pointer-equality, the structural invariant
        // the subset-to-superset composition was lifted to make
        // load-bearing on the type system rather than on per-callsite
        // discipline.
        for uf in UnquoteForm::ALL {
            let from_marker = uf.marker();
            let from_composition = uf.to_quote_form().prefix();
            assert_eq!(
                from_marker, from_composition,
                "UnquoteForm::{uf:?}.marker() bytes drifted from .to_quote_form().prefix() bytes — the subset's diagnostic vocabulary is no longer derived from the superset's canonical site",
            );
            assert!(
                std::ptr::eq(from_marker.as_ptr(), from_composition.as_ptr()),
                "UnquoteForm::{uf:?}.marker() and .to_quote_form().prefix() disagree on `&'static str` address — pointer drift means the lift composes through a parallel literal table rather than routing into the canonical QuoteForm::prefix site",
            );
        }
    }

    #[test]
    fn unquote_form_per_role_markers_alias_quote_form_per_role_prefixes_byte_for_byte() {
        // ALIAS CONTRACT: pin both per-role `pub const UnquoteForm::*_MARKER`
        // aliases equal the corresponding `pub const QuoteForm::*_PREFIX`
        // byte-for-byte — so the UnquoteForm ⊂ QuoteForm marker-vocabulary
        // containment routes through the typed
        // `pub const UnquoteForm::V_MARKER: &'static str = QuoteForm::V_PREFIX`
        // alias chain rather than through two independent literal-discipline
        // sites. A regression that renames the QuoteForm side without
        // updating the UnquoteForm alias pointing at it fails-loudly here
        // with the exact axis identified (UNQUOTE / SPLICE); a regression
        // that re-inlines the UnquoteForm constant to a fresh literal still
        // passes this pin but loses the alias-chain typing (which is what
        // `unquote_form_marker_arms_route_through_per_role_markers_for_every_variant`
        // + `unquote_form_markers_align_with_all_by_index` catch in
        // combination).
        //
        // Sibling posture to
        // `atom_kind_per_role_labels_alias_sexp_shape_per_role_labels_byte_for_byte`
        // (commit fc126b8): both pin the invariant that a typed-subset
        // enum's per-role bytes are structurally derived from the parent
        // superset's per-role bytes via a `pub const = Parent::CONST`
        // alias rather than through parallel literal tables. The subset
        // there is AtomKind ⊂ SexpShape (6-of-12 on the atomic-payload
        // axis); the subset here is UnquoteForm ⊂ QuoteForm (2-of-4 on
        // the template-substitution axis) — both are load-bearing
        // structural carvings whose per-role vocabularies MUST agree
        // byte-for-byte with their parent's.
        use crate::ast::QuoteForm;
        assert_eq!(UnquoteForm::UNQUOTE_MARKER, QuoteForm::UNQUOTE_PREFIX);
        assert_eq!(UnquoteForm::SPLICE_MARKER, QuoteForm::UNQUOTE_SPLICE_PREFIX);
    }

    #[test]
    fn unquote_form_marker_arms_route_through_per_role_markers_for_every_variant() {
        // PATH-UNIFORMITY: `UnquoteForm::V.marker()` MUST equal the
        // per-role `pub const UnquoteForm::V_MARKER` for every
        // `v: UnquoteForm`. Pre-lift the two template-marker bytes
        // were reachable through `UnquoteForm::marker` (the composition
        // `self.to_quote_form().prefix()` — routing into
        // `QuoteForm::UNQUOTE_PREFIX` / `UNQUOTE_SPLICE_PREFIX`) OR
        // through direct `QuoteForm::UNQUOTE_PREFIX` reach-across;
        // post-lift each variant's canonical bytes are reachable
        // through the per-role `UnquoteForm::*_MARKER` alias too. Pin
        // the byte-equality between the runtime projection and the
        // compile-time alias so a regression that renames the alias
        // without updating the arm (or vice versa) fails-loudly at
        // the exact axis.
        //
        // Sibling-shape pin to
        // `atom_kind_label_arms_route_through_per_role_labels_for_every_variant`
        // one algebra layer over — the AtomKind subset algebra's per-
        // role aliases are pinned against `AtomKind::label`'s
        // composition-routed arms there; this pin binds the
        // UnquoteForm subset algebra's per-role aliases against
        // `UnquoteForm::marker`'s composition-routed arms so the two
        // template-marker bytes project through ONE aliased typed
        // source of truth per role rather than through per-consumer
        // inline literals.
        assert_eq!(UnquoteForm::Unquote.marker(), UnquoteForm::UNQUOTE_MARKER);
        assert_eq!(UnquoteForm::Splice.marker(), UnquoteForm::SPLICE_MARKER);
    }

    #[test]
    fn unquote_form_markers_has_expected_cardinality() {
        // Cardinality pin: `MARKERS.len() == 2` matches `ALL.len()` so
        // a refactor that loosens the type to `&'static [&'static str]`
        // fails HERE (the `[_; 2]` slot cannot be sliced silently),
        // and a variant added to `ALL` without a matching `MARKERS`
        // row fails the pair-arity gate at the array literal itself
        // before this test even runs. The pin doubles as an operator-
        // visible mark of the family's cardinality across the
        // substrate — two template markers, matching the 2-of-4
        // carving of the parent `QuoteForm::PREFIXES` (the
        // substitution-subset of the four canonical homoiconic prefix
        // bytes).
        assert_eq!(UnquoteForm::MARKERS.len(), 2);
        assert_eq!(UnquoteForm::MARKERS.len(), UnquoteForm::ALL.len());
    }

    #[test]
    fn unquote_form_markers_align_with_all_by_index() {
        // ALIGNMENT PIN: sweep `MARKERS[i] == ALL[i].marker()` so any
        // `zip(ALL, MARKERS)` consumer reads a coherent (variant,
        // marker) pair off ONE forced-arity array pair. The
        // declaration-order pin makes a family-wide consumer that
        // walks the ALL / MARKERS pair in lockstep (an LSP completion
        // bar keyed on `UnquoteForm::MARKERS`, a Sekiban metric
        // emitter labeling
        // `tatara_lisp_unbound_template_var_total{prefix}` by the
        // per-index marker) read one canonical (variant, bytes) pair
        // per slot rather than routing through per-consumer paired-
        // iteration. A regression that reorders MARKERS without also
        // reordering ALL (or vice versa) fails-loudly at the exact
        // index that drifted.
        assert_eq!(UnquoteForm::MARKERS.len(), UnquoteForm::ALL.len());
        for (i, form) in UnquoteForm::ALL.iter().enumerate() {
            assert_eq!(
                UnquoteForm::MARKERS[i],
                form.marker(),
                "UnquoteForm::MARKERS[{i}] `{mkr}` drifted from \
                 UnquoteForm::ALL[{i}].marker() `{via_variant}` — the \
                 canonical ALL ordering and the MARKERS ordering must \
                 match element-wise",
                mkr = UnquoteForm::MARKERS[i],
                via_variant = form.marker(),
            );
        }
    }

    #[test]
    fn unquote_form_markers_pairwise_distinct() {
        // 2x2 pairwise sweep so a collision between the two markers
        // (which would silently degrade two distinct template-
        // substitution markers to the SAME diagnostic bytes and
        // violate the closed-set FromStr round-trip) fails-loudly at
        // the exact pair. Distinctness is already enforced
        // structurally by `assert_closed_set_well_formed::<UnquoteForm>()`
        // (clause 3), so this pin is a secondary guard focused on the
        // per-role `pub const` surface directly rather than the
        // runtime projection through the trait's default `labels()`.
        for (i, a) in UnquoteForm::MARKERS.iter().enumerate() {
            for (j, b) in UnquoteForm::MARKERS.iter().enumerate() {
                if i == j {
                    continue;
                }
                assert_ne!(
                    a, b,
                    "UnquoteForm::MARKERS[{i}] ({a:?}) collides with \
                     UnquoteForm::MARKERS[{j}] ({b:?}) — two distinct \
                     template markers cannot share diagnostic bytes",
                );
            }
        }
    }

    #[test]
    fn unquote_form_unquote_lead_aliases_quote_form_unquote_lead_byte_for_byte() {
        // ALIAS CONTRACT: pin the sole per-role
        // `pub const UnquoteForm::UNQUOTE_LEAD` alias equals
        // `pub const QuoteForm::UNQUOTE_LEAD` byte-for-byte — so the
        // UnquoteForm ⊂ QuoteForm reader-lead-char vocabulary
        // containment routes through the typed
        // `pub const UnquoteForm::UNQUOTE_LEAD: char =
        // QuoteForm::UNQUOTE_LEAD` alias chain rather than through an
        // independent literal-discipline site. A regression that
        // renames the QuoteForm side (a hypothetical repartitioning
        // that swaps the substitution-family lead byte from `,` to a
        // different char) without updating the UnquoteForm alias
        // pointing at it fails-loudly here; a regression that re-
        // inlines the UnquoteForm constant to a fresh `','` literal
        // still passes this pin but loses the alias-chain typing
        // (which is what the routing pin below catches in
        // combination).
        //
        // Sibling posture to
        // `unquote_form_per_role_markers_alias_quote_form_per_role_prefixes_byte_for_byte`
        // (commit 3640f76 — reader-punctuation-prefix axis),
        // `unquote_form_per_role_iac_forge_tags_alias_quote_form_per_role_iac_forge_tags_byte_for_byte`
        // (commit 6acab84 — iac-forge canonical-form axis),
        // `unquote_form_per_role_labels_alias_quote_form_per_role_labels_byte_for_byte`
        // (commit da68af5 — diagnostic-label axis), and
        // `unquote_form_per_role_hash_discriminators_alias_quote_form_per_role_hash_discriminators_byte_for_byte`
        // (commit eca4730 — outer-`Sexp` cache-key axis) — this
        // FIFTH alias-contract pin closes the QUINTUPLE of per-role
        // `pub const` axes on the UnquoteForm subset carving.
        assert_eq!(
            UnquoteForm::UNQUOTE_LEAD,
            crate::ast::QuoteForm::UNQUOTE_LEAD,
            "UnquoteForm::UNQUOTE_LEAD drifted from QuoteForm::UNQUOTE_LEAD — the alias chain broke",
        );
    }

    #[test]
    fn unquote_form_unquote_lead_pins_canonical_reader_lead_char() {
        // Byte-for-byte pin of the canonical
        // (UnquoteForm, reader-lead char) mapping at the per-role
        // `pub const` axis: `UnquoteForm::UNQUOTE_LEAD == ','` — the
        // exact char the reader's outer tokenizer dispatch selects
        // template-substitution-family entry on. This char is
        // load-bearing: the reader's outer tokenizer pre-check
        // (`QuoteForm::from_lead_char(ch)`) routes into the
        // substitution-family branch iff `ch == UNQUOTE_LEAD`, and
        // the `,`-vs-`,@` disambiguation lives at the reader's
        // peek-then-consume `@` second-char step (promoting the
        // default `Unquote` return into a `Splice` on `@`). A
        // regression that drifts this const from `,` silently
        // fractures the reader's outer dispatch AND the
        // `PROMOTIONS[0].1 == UNQUOTE_LEAD.next_char_promoter_source`
        // structural pairing that the promotion table binds to.
        // Sibling of
        // `unquote_form_per_role_hash_discriminators_pin_legacy_cache_key_bytes`
        // (which pins the outer-`Sexp` cache-key bytes at the
        // per-role `pub const` axis) — this test pins the reader-
        // lead char on the same axis one production vocabulary over.
        assert_eq!(
            UnquoteForm::UNQUOTE_LEAD,
            ',',
            "UnquoteForm::UNQUOTE_LEAD drifted from legacy reader-lead char ','",
        );
    }

    #[test]
    fn unquote_form_unquote_lead_routes_through_to_quote_form_lead_char_via_composition() {
        // Post-lift composition pin: for every `uf: UnquoteForm`,
        // `UnquoteForm::UNQUOTE_LEAD` and
        // `uf.to_quote_form().lead_char()` agree byte-for-byte — the
        // (subset marker, reader-lead char) pairing rides through the
        // superset's canonical `QuoteForm::lead_char` closed-set
        // match rather than through a parallel two-arm inline table
        // on the subset. A regression that re-inlines the two arms
        // as a parallel match-table (e.g. a future edit that spells
        // `Self::Unquote => ',' / Self::Splice => ','` directly at
        // `UnquoteForm::lead_char` instead of routing through
        // `self.to_quote_form().lead_char()`) is caught here — both
        // subset variants project to the SAME parent-superset lead
        // byte at
        // [`crate::ast::QuoteForm::lead_char`]'s
        // `Self::Unquote | Self::UnquoteSplice => Self::UNQUOTE_LEAD`
        // MERGED arm, and this composition pin binds that merge on
        // the subset carving. Sibling-shape pin to the four prior-
        // lift composition pins on `UnquoteForm`:
        // `unquote_form_marker_routes_through_to_quote_form_prefix_via_composition`,
        // `unquote_form_iac_forge_tag_routes_through_to_quote_form_iac_forge_tag_via_composition`,
        // `unquote_form_label_routes_through_to_quote_form_label_via_composition`,
        // and
        // `unquote_form_hash_discriminator_routes_through_to_quote_form_hash_discriminator_via_composition`
        // — all five pin the subset's projection through the
        // superset's canonical site via the same typed composition
        // posture. The FIFTH composition-through-`to_quote_form`
        // axis on the substitution-subset closed set is now load-
        // bearing on the type system.
        for uf in UnquoteForm::ALL {
            let via_composition = uf.to_quote_form().lead_char();
            assert_eq!(
                UnquoteForm::UNQUOTE_LEAD, via_composition,
                "UnquoteForm::{uf:?} projects through .to_quote_form().lead_char() = `{via_composition}` — but UnquoteForm::UNQUOTE_LEAD = `{}` — the SHAPE-ASYMMETRIC-COLLAPSE identity (both subset arms → one lead byte) broke",
                UnquoteForm::UNQUOTE_LEAD,
            );
        }
    }

    #[test]
    fn unquote_form_leads_has_expected_shape_asymmetric_cardinality() {
        // Cardinality pin: `LEADS.len() == 1` — the SHAPE-ASYMMETRIC-
        // COLLAPSE cardinality that IS the collapse witness on the
        // 2-of-4 subset carving. UnquoteForm has 2 arms
        // (`Self::ALL.len() == 2`), but both arms share the same
        // reader-lead byte `,`, so the distinct-lead-byte closed-set
        // ALL array collapses to `[char; 1]`. The cardinality gap
        // `Self::ALL.len() (== 2) - Self::LEADS.len() (== 1) == 1`
        // IS the shared-lead-char invariant carried at the type-
        // system level.
        //
        // Peer to `unquote_form_markers_has_expected_cardinality`
        // (which pins `MARKERS.len() == 2 == ALL.len()` — the
        // arm-per-arm axis has NO collapse), this test pins the
        // OPPOSITE `LEADS.len() == 1 < ALL.len()` invariant — the
        // distinct-lead-set axis DOES collapse. The two axes together
        // fully characterize the reader-vocabulary shape on the
        // UnquoteForm closed set.
        //
        // Peer to `quote_form_leads_has_expected_shape_asymmetric_cardinality`
        // (parent 4-of-4 carving pins `QuoteForm::LEADS.len() == 3`
        // for 4 arms — the same shared-lead-byte collapse identity
        // one algebra level up).
        assert_eq!(
            UnquoteForm::LEADS.len(),
            1,
            "UnquoteForm::LEADS cardinality drifted from 1 — the shared-lead-char collapse invariant on the 2-of-4 substitution-subset carving is broken",
        );
        assert!(
            UnquoteForm::LEADS.len() < UnquoteForm::ALL.len(),
            "UnquoteForm::LEADS.len() ({leads}) MUST be strictly less than UnquoteForm::ALL.len() ({all}) — the SHAPE-ASYMMETRIC-COLLAPSE identity requires a strict cardinality gap",
            leads = UnquoteForm::LEADS.len(),
            all = UnquoteForm::ALL.len(),
        );
    }

    #[test]
    fn unquote_form_leads_covers_all_variants_via_to_quote_form_lead_char() {
        // COVERAGE pin: every UnquoteForm variant's reader-lead byte
        // (projected through the superset composition
        // `self.to_quote_form().lead_char()`) MUST appear in
        // `UnquoteForm::LEADS`. Combined with the cardinality pin
        // above (`LEADS.len() == 1`), this pins that `LEADS` is
        // EXACTLY the image of `ALL` under the composition — no
        // superfluous entries, no missing coverage. A regression
        // that adds a spurious char to `LEADS` (e.g. a future edit
        // that includes both `,` and `@` in the array under the
        // mistaken belief that `,@` is a separate lead byte) fails
        // the cardinality pin above; a regression that DROPS the
        // sole entry from `LEADS` fails this coverage pin at every
        // variant.
        for uf in UnquoteForm::ALL {
            let lead = uf.to_quote_form().lead_char();
            assert!(
                UnquoteForm::LEADS.contains(&lead),
                "UnquoteForm::{uf:?} projects through .to_quote_form().lead_char() = `{lead}` — but UnquoteForm::LEADS ({leads:?}) does NOT contain `{lead}`; the distinct-lead-byte ALL array must cover every variant's lead byte",
                leads = UnquoteForm::LEADS,
            );
        }
    }

    #[test]
    fn unquote_form_leads_is_subset_of_quote_form_leads() {
        // CONTAINMENT pin: `UnquoteForm::LEADS` is a subset of
        // `QuoteForm::LEADS` — the substitution-subset carving's
        // reader-lead-byte set sits inside the parent QuoteForm
        // superset's reader-lead-byte set by the UnquoteForm ⊂
        // QuoteForm inclusion. The sole entry `UnquoteForm::LEADS[0]
        // == ','` must equal `QuoteForm::UNQUOTE_LEAD`, which IS the
        // third entry `QuoteForm::LEADS[2]` (Quote/Quasiquote/Unquote
        // in declaration order per `QuoteForm::LEADS`). A regression
        // that drifts `UnquoteForm::UNQUOTE_LEAD` out of alignment
        // with the parent (e.g. a future edit that inlines a fresh
        // `';'` literal into the UnquoteForm alias but leaves
        // QuoteForm's canonical byte at `','`) fails-loudly here.
        // Sibling of
        // `unquote_form_hash_discriminator_partitions_disjointly_from_non_substitution_carvings`
        // (which pins the cache-key axis's partition-membership on
        // the same subset carving) — this test pins the reader-lead-
        // byte axis's subset-membership one production vocabulary
        // over.
        use crate::ast::QuoteForm;
        for lead in UnquoteForm::LEADS {
            assert!(
                QuoteForm::LEADS.contains(&lead),
                "UnquoteForm::LEADS entry `{lead}` MUST appear in QuoteForm::LEADS ({parent:?}) — the UnquoteForm ⊂ QuoteForm subset-inclusion breaks otherwise",
                parent = QuoteForm::LEADS,
            );
        }
    }

    #[test]
    fn unquote_form_leads_matches_to_quote_form_lead_char_image_exactly() {
        // EXACT-IMAGE pin: `UnquoteForm::LEADS` as an unordered set
        // equals the image of `UnquoteForm::ALL` under
        // `.to_quote_form().lead_char()`. Combined with the
        // cardinality pin (`LEADS.len() == 1`) and the coverage pin
        // (every variant's lead appears in LEADS), this ties LEADS
        // to the composition's image at the SET level — a regression
        // that reorders entries, adds duplicates, or drops entries
        // fails at exactly one of the three pins.
        use std::collections::HashSet;
        let leads_set: HashSet<char> = UnquoteForm::LEADS.iter().copied().collect();
        let image_set: HashSet<char> = UnquoteForm::ALL
            .iter()
            .map(|uf| uf.to_quote_form().lead_char())
            .collect();
        assert_eq!(
            leads_set, image_set,
            "UnquoteForm::LEADS ({leads_set:?}) as a set MUST equal the image of UnquoteForm::ALL under .to_quote_form().lead_char() ({image_set:?}) — the distinct-lead-byte closed-set ALL array drifted from its composition source",
        );
    }

